window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]=window.__LIBQ["the-gioi-hoan-my"]["q03"]||{};window.__LIBQ["the-gioi-hoan-my"]["q03"]["cotTruyen"]=[{"chuong":201,"tieuDe":"Vô Đề","tomTat":"Đêm trăng bên hồ Thạch thôn, Nhóc Tỳ dùng rượu Hầu Nhi cùng phương pháp cổ trong Nguyên Thủy Chân Giải vỗ hòa tan dược lực, trị dứt ám tật kín lâu năm cho tộc trưởng Thạch Vân Phong — một luồng tro bụi phun ra từ miệng lão, lão phục hồi mạnh mẽ như trẻ lại hai mươi tuổi, hé lộ năm đó hơn mười huynh đệ chỉ mình lão sống sót trở về mà mắc bệnh kỳ dị. Nhóc Tỳ tặng thôn dân hơn mười kiện bảo cụ chiến lợi phẩm, gồm kiếm đỏ luyện từ răng nanh Phì Di và sừng thú đoạt từ đệ tử Võ Vương phủ, rồi cùng Thanh Phong trồng cây đào tiên và Ngân Đào thụ chuẩn Thánh dược giữa thôn, vùi bùn cát vàng kim nuôi dưỡng. Sáng hôm sau con Bát Trân Kê thành tinh sổng khỏi túi Càn Khôn, biết độn thổ; Hổ thẩm đòi hầm gà nhưng Nhóc Tỳ ngăn cản vì trứng nó sánh linh dược, cả Thạch quốc chỉ hoàng thất mới có một con. Con gà nằm lười dưới gốc liễu, quỳ lạy thần thụ và coi thường Đại Hồng Điểu. Sau đó Nhóc Tỳ khổ sở vì tháp nhỏ trắng nuốt huyết nhục bảo dược thuần huyết mà không nhả, tự cắn lẫn nhờ Bóng Lông cắn đều vô hiệu, cuối cùng phải nhờ Liễu Thần xem giúp. Liễu Thần trịnh trọng định giá tháp này xuất hiện từ thời Thái Cổ, hiển hóa cả thời Thượng Cổ, có thần uy cái thế."},{"chuong":202,"tieuDe":"Thuần Huyết","tomTat":"Nhóc Tỳ kinh ngạc trước địa vị của Tiểu Tháp và gạn hỏi Liễu Thần về lai lịch cùng thời đại của nó, nhưng bị cảnh cáo không nên dò xét đến cùng kẻo gặp đại họa sát thân, chỉ cần biết đó là bảo cụ thần uy cái thế. Liễu Thần tiết lộ Tiểu Tháp thiếu vài tầng so với nguyên bản, hiện chỉ còn bốn tầng và đang tự chữa trị bằng cách hấp thụ tinh hoa huyết nhục sinh linh. Đòi lại huyết nhục Thôn Thiên Tước và Cùng Kỳ bị Tiểu Tháp nuốt, Nhóc Tỳ chứng kiến Liễu Thần điều khiển Tiểu Tháp nhả ra bột xương vô giá cùng các khối huyết nhục mấy ngàn cân, rồi dùng cành liễu luyện hóa bốn khối huyết nhục thuần huyết thành bốn giọt thần dịch cô đặc quý hơn hơn mười thái cổ di chủng. Bốn giọt thần dịch được chuẩn bị cho việc tẩy lễ mà Liễu Thần từng hứa với Hùng Hài Tử; huyết nhục thừa được Đại Hồng Điểu và Nhị Ngốc Tử vác đi làm tiệc. Sau đó Nhóc Tỳ khổ luyện thân thể mỗi ngày, vác tảng đá hơn mười vạn cân chạy làm mặt đất vỡ toác và nhảy giẫm nát các đỉnh núi, khiến thợ săn Thạch Thôn và Đại Hồng Điểu kinh sợ. Cuối cùng, khi hai năm trôi qua và cửa Hư Thần Giới mở lại, Liễu Thần dùng cành liễu xuyên thủng bầu trời mở lối, Nhóc Tỳ hân hoan tiến vào một khu phế tích để trở lại nơi từng bị đuổi ra."},{"chuong":203,"tieuDe":"Trở Lại Hư Thần Giới","tomTat":"Sau hai năm lẻ một tháng hết hạn cấm cửa, Nhóc Tỳ băng qua thái cổ thần sơn đổ nát rồi dùng thông đạo màu vàng dịch chuyển về Sơ Thủy Địa, ngồi xổm trên tảng đá xanh cũ khảm bảo cốt để hoài niệm chứ không dám đào lại. Dò hỏi, nó xác nhận Bổ Thiên Các đã bị chư giáo liên thủ đại phá — sư huynh sư tỷ, trưởng lão và cả lão tổ đều chết trận để che chở môn đồ rời đi, khiến nó đau đớn. Biết tứ đại gia tộc cùng các thế lực địch đang giăng lưới ở Sơ Thủy Địa tìm cá lọt lưới, Nhóc Tỳ dùng bảo thuật của Mao Cầu đổi dung mạo thành dáng gậy trúc rồi tung tin đồn Hùng Hài Tử còn sống. Khi đám người mang sát khí ập tới truy hỏi, nó cảm ứng phù văn của tứ đại gia tộc, Vũ Tộc, Thác Bạt Tộc và đánh lạc hướng sang Điểu Gia cùng Tinh Bích đại gia. Hai lão bị vây liền đòi bán tin tức giá cao, cãi nhau tố nhau lừa đảo, và con chim trên vai Điểu Gia đập cánh đánh bay kẻ ra tay khiến cả đám không dám động, hé lộ họ là cao thủ ẩn mình. Nhóc Tỳ truyền âm bắt tay hai lão, dựng màn bán tin tức về chính mình để ép các thượng cổ đại giáo mang nguyên thủy bảo cốt hoặc bảo huyết thái cổ di chủng tới đổi, mở màn kế báo huyết thù; tin đồn lan tới cả các động thiên phúc địa cao hơn."},{"chuong":204,"tieuDe":"Thu Đại Lễ","tomTat":"Tin thằng nhỏ đầu gấu Nhóc Tỳ không chết ở Bổ Thiên Các dù chư giáo liên thủ vây ép lan nhanh từ Sơ Thủy Địa lên các động thiên phúc địa cao hơn, khiến Tứ đại gia tộc, Vũ Tộc, Thác Bạt thế gia và các thế gia cổ đều phái người tới tìm chứng cớ vì kiêng kỵ thiên phú của nó. Hai lão già bịp bợm Tinh Bích đại gia và Điểu Gia rao bán tin tung tích, đòi trao đổi bằng phù cốt hoặc bảo huyết. Khi một nhóm cường giả định dùng vũ lực bức họ nói thật và giăng bảo thuật phù văn bao vây, con chim của Điểu Gia bay lên tế xuất ánh lửa từ trời biến nơi này thành ao lửa, nướng gần chín cả nhóm khiến ai nấy đều bỏ ý định vũ lực. Phong vân tụ hội, Xích Vân công tử, đại công tử Thác Bạt Tộc và người Vũ Tộc lần lượt hàng lâm; hai lão ra giá đòi mỗi đại giáo góp một bình bảo huyết thái cổ di chủng, tổng ít nhất 15 bình mới nói tung tích. Các thế lực lần lượt đặt bình máu tím, lam quang, đỏ thẫm, vàng lên bàn đá. Nấp trong bóng tối, Nhóc Tỳ — đã đột phá cực cảnh gần như vô địch tại đây và nhận diện được khí tức Vũ Tộc — chờ số bình vượt 15 rồi vọt ra từ trên trời gom toàn bộ bàn bảo huyết vào lòng, hô đòi tiền lãi cho sư môn đã chết và hét lớn của ta của ta đều là của ta."},{"chuong":205,"tieuDe":"Đại Khai Sát Giới","tomTat":"Nhóc Tỳ nhanh tay bọc đống bình ngọc bảo huyết vào tấm da thú, rồi khi bị đối phương triển khai pháp trận sao vây khốn, nó mọc đôi cánh Côn Bằng đánh nổ các ngôi sao lớn và vọt mấy trăm trượng thoát ra. Đám đông nhận ra kẻ này chính là 'thằng nhỏ đầu gấu' sống sót sau trận huyết sát ở Bổ Thiên Các, tin tức truyền đi khắp nơi khiến người đổ về Sơ Thủy Địa của Hư Thần Giới tăng vọt. Khi Tinh Bích và Điểu Gia đứng ra đòi bảo huyết, Vũ Tộc cùng tứ đại gia tộc mắt đỏ xông tới, còn Tứ công tử Thác Bạt Tộc ôm Ly Hỏa Thần Tàm giăng lưới Ly Hỏa Tàm Ti hòng bắt sống nó. Nhóc Tỳ dùng Kim Tuyền Ba Văn Công tạo vòng xoáy vàng nuốt sạch Ly Hỏa, xé rách lưới tơ bằng tay không, rồi thi triển bảo thuật Thần Côn trói và giậm chân giết chết Tứ công tử tại chỗ. Không thể thuần phục con tằm thần, nó bóp chết Ly Hỏa Thần Tàm và cất huyết nhục làm bảo dược, khiến những kẻ tử vong nơi đây cũng bị trọng thương hao tổn nguyên khí ở thân thật. Cảm nhận khí tức quen thuộc, Nhóc Tỳ xách lên thiếu niên áo trắng Vũ Phong — thiên tài Vũ Tộc từng dẫn tộc nhân đến Bổ Thiên Các lấy oán trả ơn — giật đứt cánh tay hắn để hành hạ. Nhớ lại huyết sát kiếp năm xưa, nó phát cuồng dùng bảo thuật Côn Bằng kết hợp lôi điện tàn sát tộc nhân Vũ Tộc nổ tung thành mưa máu và truy sát nhân mã hơn mười tộc, đại khai sát giới."},{"chuong":206,"tieuDe":"Đánh Đâu Thắng Đó","tomTat":"Một liên minh tạm thời của nhiều đại giáo cùng ra tay nhưng bị Nhóc Tỳ giết liểng xiểng bằng cánh Côn Bằng và tia điện, khiến Vũ Tộc tổn thất hai ba mươi người chỉ trong nháy mắt. Vũ Tộc buộc phải bày sát trận Giao Long từ mười mấy khối nguyên thủy bảo cốt xương Giao, nhưng Nhóc Tỳ trong trạng thái Hùng Hài Tử cực cảnh chém đứt các con Giao Long rồi phóng con Toan Nghê tím to hơn núi nuốt Hôi Giao, làm phù cốt nứt vỡ. Nó giết sạch người Vũ Tộc, chỉ chừa Vũ Phong rồi xé đôi tên này; ở Cổ Quốc hiện thực, phủ đệ Vũ Tộc mấy chục người ho ra máu, có người rách mi tâm vì hư thân bị giết. Thác Bạt Tộc tung ra Diệt Hồn Châm — ma khí đỏ đậm giết được cả chân thân — nhưng Nhóc Tỳ né tránh rồi dùng đỉnh lôi điện tím hút lấy mười hai cây thần châm và dùng phù văn mi tâm khống chế, đoạt luôn khỏi tay địch. Nó tuyên bố chỉ dành châm cho cao tầng các giáo, chặn trước thông đạo màu vàng không cho ai thoát khỏi Hư Thần Giới. Điều khiển toàn lực bảo thuật Côn Bằng cùng sóng biển đen, Nhóc Tỳ áp chế mọi sát trận trấn giáo và diệt sạch cao thủ chư giáo không sót một ai trong Sơ Thủy Địa. Cuối cùng bia đá hiện chữ báo lập kỷ lục giết chóc, một luồng hào quang mông lung từ trời giáng xuống mang theo một vật thần bí rơi tới gần nó, còn người các đại giáo ở hiện thực thì tức đến ói máu, thương thế nặng thêm."},{"chuong":207,"tieuDe":"Sách Thần Thái Cổ","tomTat":"Sau khi Nhóc Tỳ một mình diệt sạch hơn mười nhóm thế lực cùng hàng trăm cao thủ tại Vùng đất ma quỷ, đám người xem chiến đều nhục nhã vì trở thành bàn đạp cho chiến tích của nó, tin tức lan khắp Hư Thần Giới lẫn các Cổ Quốc khiến Sơ Thủy Địa sôi trào. Pháp tắc trật tự thế giới cảm ứng kỷ lục vừa lập, ban xuống một chùm sáng nứt ra để lộ mảnh đồng thau dị thường cực cứng, với bia đá hiện bốn chữ Đấu Chiến Tiểu Thánh và chú thích rằng đây là một phần mười của sách thần thời Thái Cổ. Tinh Bích đại gia giả thế ngoại cao nhân đòi giúp đánh giá, Điểu Gia đề nghị đổi một môn bảo thuật tuyệt thế, nhưng Nhóc Tỳ cảnh giác ôm chặt mảnh vỡ, gọi Tinh Bích là lão già lừa đảo và đe dọa không cho ai lại gần. Có người tiết lộ gom đủ toàn bộ mảnh vỡ đồng thau sẽ mở ra một tòa tiên tàng chứa bảo thuật cái thế Thái Cổ, nhưng phải tiếp tục phá những kỷ lục gian nan bất khả. Nhóc Tỳ hớn hở tuyên bố giết xong Sơ Thủy Địa sẽ tiến vào các động thiên phúc địa khác để phá thêm kỷ lục, khiến Vũ Tộc, Thác Bạt Tộc và tứ đại gia tộc biến sắc và mưu tính chờ nó lên cảnh giới Động Thiên sẽ ra tay giết cả hư thân lẫn chân thân, mở màn cho một trận giông bão đang dâng lên."},{"chuong":208,"tieuDe":"Không Còn Lo Âu","tomTat":"Các lão tổ gia tộc Thượng Cổ chấn động khi một mảnh sách quý đồng thau xuất hiện, bàn tán rằng Nhóc Tỳ bộc phát quá sớm có thể suy tàn khi lên Động Thiên Cảnh, còn Vũ Tộc và Thác Bạt Tộc thì mong ngóng một trận đại chiến với nó. Tại Sơ Thủy Địa, Nhóc Tỳ gài bẫy Tinh Bích đại gia và Điểu gia bằng cách công khai lấy ra bảo huyết di chủng Thái Cổ trước đám đông đại giáo, khiến hai lão bị nghi lừa gạt chư giáo mà không dám nhận. Khi hai lão nổi giận ra tay, Nhóc Tỳ phản kích bằng thập tinh quán nhật và sấm chớp tinh khiết làm Điểu gia cháy đen, còn nhổ trụi nửa bộ lông thần tước năm màu, trong khi Tinh Bích đại gia không dám can thiệp. Cuối cùng nó giao bảo huyết, cho hai lão xem một góc vỡ sách đồng thau và bí mật thương lượng, mời cả hai làm hộ pháp bảo vệ thôn — thu hoạch lớn nhất khiến nó hoàn toàn yên tâm. Trở về thôn dưới Liễu Thần, Nhóc Tỳ hứa dẫn cả thôn vào Hư Thần Giới, tặng hơn mười bình bảo huyết để mọi người gột rửa thân thể. Sáng hôm sau, cả thôn hành lễ Liễu Thần rồi cùng qua thông đạo màu vàng đến Sơ Thủy Địa, đám thiếu niên gây náo loạn như cả một bầy Hùng Hài Tử. Nhóc Tỳ giao đám thiếu niên ngang bướng cho hai lão hộ pháp, rồi mở thông đạo màu vàng tuyên bố đi động thiên phúc địa cao cấp hơn để đánh hạ một giang sơn to lớn và biến mất, khiến Sơ Thủy Địa sôi trào."},{"chuong":209,"tieuDe":"Động Thiên Phúc Địa","tomTat":"Nhóc Tỳ theo thông đạo màu vàng tiến vào động thiên phúc địa cao cấp của Hư Thần Giới, khiến Sơ Thủy Địa sôi trào và cả Hư Thần Giới lẫn Cổ Quốc chấn động vì xác nhận nó hành động thật. Tại hoàng cung Hỏa Quốc, Hỏa Linh Nhi tức giận vì bị gọi là mập, trách sói con nghe lời tên kia và quyết đi Hư Thần Giới xem nó ăn quả đắng; đồng thời một thiếu nữ áo tím tỉnh dậy từ động phủ trên thần sơn, tỏ ý ghét Hùng Hài Tử. Các tộc như Vũ Tộc, Thác Bạt Tộc mưu tính đuổi sói nuốt hổ bằng cách lôi kéo sinh linh Thái Cổ thuần huyết, nhưng ngại Thần Sơn Thái Cổ là cấm địa không ai dám đụng. Nhóc Tỳ khám phá thế giới thần giới linh khí dày đặc, ăn thử linh dược thấy tinh khí tăng, rồi tới Động Thiên Thành nện chân làm nứt nham thạch và bị bia đá Hư Thần Giới cảnh cáo trục xuất. Nó tuyên bố mỗi gia tộc phải nộp mười bình bảo huyết di chủng trong một canh giờ, chọn Vũ Tộc làm mục tiêu báo thù đầu tiên vì từng hãm hại Bổ Thiên Các. Hết hạn, Hùng Hài Tử tuyên chiến thảo phạt diệt sạch Vũ Tộc và xóa tên khu động thiên phúc địa, trong khi Vũ Tộc bày đại sát trận và nhắc tới Nghị nhi đã rời Thánh Viện Thượng Cổ như át chủ bài. Nhóc Tỳ chuẩn bị mười hai cây Diệt Hồn Châm rồi rút thanh kiếm gãy màu đen bổ mạnh vào tịnh thổ Vũ Tộc, kiếm khí như dãi ngân hà chém thẳng xuống, mở màn trận đấu."},{"chuong":210,"tieuDe":"Một Mình Chiến Vũ Tộc","tomTat":"Nhóc Tỳ một mình xông vào tịnh thổ Vũ Tộc trong Hư Thần Giới, vung kiếm gãy tạo kiếm khí như đại dương chém đôi quần thể kiến trúc, phá vỡ sát trận Vũ Tộc bày sẵn. Nó dùng bảo thuật Côn Bằng phóng linh vũ vàng giết gần trăm người Vũ Tộc, buộc tộc dùng Thủy Mặc Già Thiên chắn đòn; đòn giết này khiến chân thân Vũ Tộc bên ngoài trong Vũ Điểm phủ ở Cổ Quốc bị trọng thương liên lụy. Khi Vũ Tộc tế ra Ngân Thiên Lang từ tấm da dị chủng Thái Cổ, Nhóc Tỳ dùng bảo phiến máu cướp của Uyên Tộc thiêu nó thành Hỏa Lang rồi đánh gãy xương sống, buộc tộc thu hồi bảo cụ chỉ còn tấm da sói cháy thủng lỗ. Nhóc Tỳ đứng trước tịnh thổ mắng Vũ Tộc hèn nhát co đầu rút cổ, làm mất mặt cả đại tộc Vương Hầu trước quần hùng đang quan sát. Vũ Tộc phản kích bằng sát trận vô lượng và một tòa pháo đài bảo cốt, nhưng Nhóc Tỳ dùng kiếm gãy đánh nổ tung chí bảo trấn tộc này, khiến các lão Vũ Tộc phun máu; đồng thời Vũ Tộc kinh hoàng nhận ra kiếm gãy rất giống thanh kiếm của Thủy Tổ Bổ Thiên Các. Nhóc Tỳ tiếp tục dùng chín tòa Động Thiên đoạt tạo hóa tấn công tịnh thổ, trong khi một lão tổ Vũ Tộc quyết chỉ được thắng không được bại, nhắc tới việc chờ Nghị nhi xuất quan và quyết đi nghênh Pháp Chỉ Thần Linh để diệt cả hư thân lẫn chân thân của Nhóc Tỳ."},{"chuong":211,"tieuDe":"Pháp Chỉ Của Thần Linh","tomTat":"Ở nơi sâu nhất Vũ Tộc ngoài thế giới hiện thực có một miếu thần phát sáng như đúc bằng vàng thờ Vũ Thần — vị thần tổ truyền ngôn đã chết trong trận chiến Thượng Cổ. Lão tổ Vũ Tộc dẫn đám người cúng bái rồi mở chiếc bình đen chứa mười tờ giấy vàng đất nát bét ghép thành pháp chỉ cuối cùng của Vũ Thần, cho mọi người nhỏ máu chứng minh hậu duệ. Thiếu nữ thông linh Vũ Tử Mạch nhắm mắt chọn tờ pháp chỉ ghi chữ “Phạt”, đủ mạnh chém mọi địch thủ trong Hư Thần Giới. Trong Hư Thần Giới, đại trận Vũ Tộc triệu các di chủng Thái Cổ cản Nhóc Tỳ, kiếm gãy không công phá nổi phù văn còn điên cuồng nuốt tinh khí thần của nó. Nhóc Tỳ lộ Động Thiên trước quần hùng, tăng từ năm tòa lên bảy rồi mở tới chín tòa dung nham khiến quần hùng chấn kinh vì điều này chỉ ghi trong sách cổ với Nhân Tộc. Vũ Tộc thu trận rồi bộc phát pháp chỉ Thần Linh chữ “Phạt”, ảnh hưởng cả quy tắc trật tự Hư Thần Giới và trút mưa ánh sáng vàng đánh Nhóc Tỳ đầy lỗ máu. Dù bị thương, Nhóc Tỳ không lùi mà chửi mắng, liều mạng tiến lên quyết chém nát pháp chỉ, lý luận rằng Vũ Thần đã chết nên tờ giấy nát không thể nghịch thiên; phương xa thiếu nữ áo tím từ Thần Sơn Thái Cổ và thiếu nữ áo đỏ ôm sói con đờ người chứng kiến."},{"chuong":212,"tieuDe":"Xúc Phạm Thần Linh","tomTat":"Nhóc Tỳ buông lời mắng chửi thách thức Thần Linh của Vũ Tộc, dùng kiếm gãy tuôn hàng trăm ngàn vệt kiếm khí bổ vào pháp chỉ chữ ‘Phạt’ và đánh bay tờ bùa xa mấy trăm trượng, khiến cả Vũ Tộc kinh hãi vì một đứa bé lại chống được pháp chỉ Vũ Thần. Đám già Vũ Tộc trong vùng tịnh thổ ngồi xếp bằng ngâm thần chú Tế Vũ Thần khiến pháp chỉ thức tỉnh mạnh hơn, hóa thành vầng mặt trời vàng óng phun mưa mặt trời màu vàng và lôi điện. Nhóc Tỳ thi triển bảo thuật Côn Bằng hợp nhất kiếm gãy há miệng nuốt pháp chỉ khiến tờ giấy tạm biến mất, nhưng nó hồi phục với một vết rách rồi tiếp tục phóng chữ ‘Phạt’ như bảo cụ và tia chớp như dải ngân hà. Nhóc Tỳ triển Toan Nghê màu tím cao bằng núi lớn cắn nuốt tia chớp và xé chữ ‘Phạt’, dù bị đánh thủng hơn hai mươi lỗ máu thân thể gần nát vẫn kiên trì không lùi. Trước đòn cuối là ngôi sao lớn của pháp chỉ, kiếm gãy rốt cuộc thức tỉnh cắt tờ giấy thành hai nửa, tiểu tháp trên sợi tóc va chạm ngăn được chữ ‘Phạt’. Cuối cùng nơi ngực Nhóc Tỳ bùng phát khí tức đáng sợ như hố đen nuốt chửng chữ ‘Phạt’, tinh huyết Chí Tôn không ngừng tăng cường, thai nghén ra sinh cơ vô tận."},{"chuong":213,"tieuDe":"Tư Chất Ngút Trời","tomTat":"Ngực Nhóc Tỳ nóng rực, lồng ngực trong suốt hé lộ Chí Tôn Cốt — khối xương chưa thành hình được máu tươi thai nghén — đang rút tinh hoa thần tính chữ “Phạt” của pháp chỉ Thần Linh để tẩm bổ, nhưng tinh hoa không trọn vẹn nên chưa đủ lột xác. Pháp chỉ vỡ nát, Nhóc Tỳ sống sót khiến Vũ Tộc và quần hùng kinh ngạc, rồi nó nhai nuốt cả hai nửa tờ giấy khiến các lão giả Vũ Tộc hộc máu; Hỏa Linh Nhi ví nó là Thao Thiết chuyển thế. Bia kỷ lục Hư Thần Giới hiện ra ghi nó chiến bại ý chí Thần Linh, ban thưởng hai miếng đồng thau Thái Cổ Thần Thư nâng tổng lên ba miếng. Nhóc Tỳ uống bảo huyết di chủng hồi phục rồi xông vào tịnh thổ, phá mười một tầng đại trận, thi triển kiếm gãy (chín Động Thiên), bảo thuật Toan Nghê và Côn Bằng giết hàng chục người, dùng Diệt Hồn Châm giết một nguyên lão Vũ Tộc thân phận cực cao. Một ông lão nham hiểm kích nổ cấm trận trung tâm, giết hơn trăm cao thủ Vũ Tộc lẫn khiến Nhóc Tỳ trọng thương gần đứt rời thân thể, còn bọn Vũ Tộc định dùng Trấn Hồn Tháp luyện hóa nó thành thân tử đạo tiêu. Trong nguy nan, Nhóc Tỳ tự đốt tinh khí thần chữa thương, bộc phát tinh khí sinh mệnh và tự mình mở tòa Động Thiên thứ mười, khiến quần hùng kinh ngạc gọi là thần thoại."},{"chuong":214,"tieuDe":"Vô Đề","tomTat":"Trong lúc giao chiến với Vũ Tộc tại Hư Thần giới, Nhóc Tỳ bất ngờ làm hiện dấu hiệu Động Thiên thứ mười, cảnh giới thần thoại vượt trên chín Động Thiên. Vũ Tộc kinh hoàng phản kích bằng vạn phù tiễn, bảo ấn hóa núi, đại trận tịnh thổ và thần chu chặn đường, nhưng lần lượt bị Toan Nghê tím, Côn Bằng và kiếm gãy của Nhóc Tỳ phá tan. Nhóc Tỳ nhận ra tòa Động Thiên thứ mười cần bản thân chủ động đoạt tạo hóa để thành hình, song chiến trường hỗn loạn khiến việc vượt ải liên tục bị quấy nhiễu. Cậu dùng đỉnh lôi điện luyện hóa và đoạt Trấn Hồn Tháp, rồi dùng Diệt Hồn Châm giết Lục thúc tổ và Tứ thúc tổ, khiến Vũ Tộc chịu tổn thất nặng. Sau đó Nhóc Tỳ đại khai sát giới bằng Toan Nghê tím và đại dương màu đen, giết hàng trăm người Vũ Tộc, ngăn họ mở đại trận cuối cùng. Khi định rút đi để chuyên tâm mở Động Thiên thứ mười, cậu bị Ly Long thuần huyết chặn đường đòi Thanh Đồng Bảo Thư, rồi lại gặp một thiếu niên Nhân Tộc lạ đã mở chín Động Thiên và mang chí bảo. Chương kết ở thế Nhóc Tỳ vừa chiến đấu với hai đối thủ mạnh vừa tiếp tục cố mở Động Thiên thứ mười, thậm chí đe dọa sẽ ăn hết cả hai nếu bị chọc giận."},{"chuong":215,"tieuDe":"Đại Địch","tomTat":"Nhóc Tỳ đang mang trọng thương sau trận đối kháng pháp chỉ Thần Linh thì bị hai đại địch vây công tại tịnh thổ Vũ Tộc: một thiếu niên Nhân Tộc thần bí có thân thể như Man Thần và một Ly Long thuộc dòng hung thú Thái Cổ. Thiếu niên Nhân Tộc ép giao Thái Cổ Thần Thư, còn Ly Long nhắm tới bảo thư đồng thau, khiến cuộc chiến xoay quanh cả sinh tử lẫn đoạt bảo. Nhóc Tỳ vận dụng cốt văn từ Nguyên Thủy Chân Giải, triệu lôi hải, Toan Nghê và Côn Bằng để đối kháng với Bệ Ngạn, Bạch Hổ cùng hoa văn hình rồng của Ly Long. Trong cận chiến, Nhóc Tỳ và thiếu niên Nhân Tộc đều bị thương nặng, máu văng khắp nơi, còn tịnh thổ Vũ Tộc càng bị tàn phá. Nhóc Tỳ nhiều lần muốn mở Động Thiên thứ mười để lột xác nhưng bị Ly Long liên tục cản phá. Khi bị Ly Long quấn chặt định nuốt, nó cắn ngược, phá nát hơn mười vảy và nuốt máu thịt đối phương, làm quần hùng kinh ngạc. Cuối chương, Nhóc Tỳ nảy ý định mượn sức hai đại địch để ép mở Động Thiên thứ mười, sau đó quét ngang các đối thủ trong khu vực."},{"chuong":216,"tieuDe":"Hi Vọng","tomTat":"Quần hùng chấn động trước Nhóc Tỳ, một thiếu niên loài người mới mười bốn mười lăm tuổi đã mở chín Động Thiên và đủ sức giao chiến với các thiên tài tuyệt đỉnh. Trong trận huyết chiến, nó bị thiếu niên dã tính thân màu đồng cổ và Ly Long vây công, cả hai đều là cường giả chín Động Thiên, khiến nó rơi vào tình thế nguy hiểm nhất từ trước đến nay. Sau khi nhận ra Động Thiên thứ mười không thể dựa vào thiên tài địa bảo mà phải tự chớp lấy tạo hóa, Nhóc Tỳ mạo hiểm dùng Kim Tuyền Ba Văn Công hút thần lực của hai đối thủ để cưỡng ép phá quan. Sóng chấn từ quá trình mở ải khiến các thế lực như Thác Bạt Tộc, Tây Lăng Thú Sơn và tứ đại gia tộc không thể lại gần, nhưng sau hơn một canh giờ, lần trùng kích ấy vẫn thất bại sát nút, làm cả ba trọng thương, riêng Nhóc Tỳ suýt thân tử đạo tiêu. Tin tức nó nhổ tận gốc tịnh thổ Vũ Tộc, giết tám phần mười cường giả và ăn cả pháp chỉ Thần Linh lan khắp Hoang Vực, khiến nhiều đại giáo liên thủ phong tỏa Hư Thần Giới, chuẩn bị ma khí để truy sát. Hỏa Linh Nhi lo lắng cho rằng nó quá liều lĩnh, bởi ngay cả sinh linh thuần huyết Thái Cổ muốn phá quan nghịch thiên cũng cần cường giả cổ lão hộ đạo. Bị truy sát suốt nửa tháng, thân thể rách nát đến mức gần như dầu cạn đèn tắt, Nhóc Tỳ bước vào tử địa, buông lỏng sinh tử và bất ngờ ngộ ra con đường niết bàn của riêng mình. Trong khoảnh khắc cận tử hồi sinh, tiềm năng ẩn giấu bùng phát, thương thế khép lại, Động Thiên thứ mười được nối liền và bắt đầu hiện ra như một vùng tiên cảnh."},{"chuong":217,"tieuDe":"Mười Động Thiên","tomTat":"Trong rừng rậm Hư Thần Giới, Nhóc Tỳ trọng thương gần chết nhưng vẫn kiên trì mở Động Thiên thứ mười. Sau nửa tháng chịu dày vò như địa ngục, nó rốt cuộc thành công, được khí lành của Động Thiên tẩm bổ, trải qua niết bàn tái sinh và khôi phục hoàn toàn. Mười Động Thiên giao hòa như mười mặt trời, đưa nó lên đỉnh cao cảnh giới Động Thiên, được gọi là Cực Cảnh. Khi tỉnh lại, Nhóc Tỳ cảm ngộ Hư Thần Giới không khác thế giới thực, những gì xảy ra ở đây cũng có thể liên hệ tới bên ngoài. Trong khi đó, Tây Lăng Thú Sơn, Thác Bạt Tộc và Vũ Tộc tung tin rằng nó đã lỡ mất cơ hội mở mười Động Thiên, khiến nhiều thế lực tin nó thất bại. Các công tử Thác Bạt dẫn hơn trăm người tới trước, Nhị công tử và Lục công tử còn cá cược ai giết Nhóc Tỳ trước, trong lúc Vũ Tộc, Ly Long, các đại giáo cổ và nhóm vì Thanh Đồng Bảo Thư cũng đang đuổi tới."},{"chuong":218,"tieuDe":"Thiếu Niên Chí Tôn","tomTat":"Các thế lực trong dãy núi cùng kéo tới săn Nhóc Tỳ vì tin rằng trên người nó có Thanh Đồng Thần Thư, bảo vật vô giá khiến Vũ Tộc, cổ thế gia Thác Bạt, Tây Lăng Thú Sơn và nhiều giáo phái cùng tranh đoạt. Họ phát hiện dấu vết máu khô trong rừng và tưởng Nhóc Tỳ đã trọng thương đến mức đèn cạn dầu, trong khi Nhóc Tỳ lại đang uất ức vì mở thành công Động Thiên thứ mười mà Hư Thần Giới không ban thưởng hay dựng bia kỷ lục. Hai công tử Thác Bạt và các lão thành hai tộc tranh nhau quyền giết Nhóc Tỳ, còn Nhị công tử cầm Diệt Hồn Châm định diệt cả hình thần đối thủ. Khi một cường giả Vũ Tộc chỉ mặt khiêu khích, Nhóc Tỳ chỉ một ngón tay đã khiến hắn nổ tung, rồi tiếp tục bộc phát thần uy Chí Tôn của mười Động Thiên. Phù văn vàng quanh người nó hóa thành vùng thần vực, phân giải bảo thuật và nghiền nát những kẻ xông tới; Lục công tử bị kéo tới và bị châm thần đỏ đâm chết, Nhị công tử cũng bị đoạt châm, đánh nát bảo cụ rồi chết dưới chính pháp bảo của mình. Cuối cùng Nhóc Tỳ dùng phù văn vàng giam giữ hư không, khiến toàn bộ đám vây săn bất động rồi nổ tung thành tro tàn, sau đó rời khỏi khu rừng trong hào quang sáng rực."},{"chuong":219,"tieuDe":"Quét Ngang","tomTat":"Vô số thế lực kéo vào khu rừng nguyên thủy để truy tìm Nhóc Tỳ, vì Thanh Đồng Bảo Thư hắn mang theo được xem là Thái Cổ Thần Thư có giá trị khó đo lường. Một nhóm liên minh tán tu tìm thấy hắn trước, tưởng hắn đã sức cùng lực kiệt nên uy hiếp đòi giao bảo thư, nhưng bị Nhóc Tỳ dùng nhãn quang xuyên phá bốn đầu lĩnh rồi triệu Toan Nghê lôi đình nuốt sạch mấy chục người. Sau đó quần hùng vây tới đông hơn, trong đó Tây Lăng Thú Sơn đưa sáu đại di chủng như Bích Lân Báo, Kim Tình Long Giác Sư và Ác Ma Viên tới đòi độc chiếm bảo thư, còn các đại giáo Nhân Tộc và gia tộc Thượng Cổ tranh chấp quyền sở hữu. Tứ đại gia tộc Côn, Ly, Mông, Uyên cũng xuất hiện với thù hận sâu, mang ma khí và vật quan trọng nhất trong tộc nhằm giết cả hư thân lẫn chân thân của Hùng Hài Tử trước khi bàn chuyện bảo thư. Nhóc Tỳ trực diện nghênh chiến, một quyền bùng sáng như thái dương đánh nổ Bích Lân Báo to như núi. Hắn tiếp tục thi triển bảo thuật Côn Bằng bằng sức mạnh mười Động Thiên, hóa lông thần thành vô số thiên kiếm vàng, giết vô số nhân mã tứ đại tộc và cướp sạch ma khí của các đầu lĩnh. Cuối chương, Nhóc Tỳ như Ma Thần đạp thi thể địch nhân tiến ra khỏi dãy núi, một mình truy sát quần hùng và quét ngang tất cả."},{"chuong":220,"tieuDe":"Chấn Động Hoang Vực","tomTat":"Nhóc Tỳ sau khi tưởng đã gần chết bất ngờ hồi phục, sức chiến đấu tăng vọt và một mình truy sát quần hùng trong dãy núi. Viện quân các giáo tới để đoạt Thanh Đồng Cổ Thư nhưng bị cảnh tượng trước mắt làm kinh hãi, rồi tiếp tục bị phù văn màu vàng của cậu nghiền ép. Nhóc Tỳ xông vào Động Thiên Thành, giết thẳng tới tịnh thổ Thác Bạt Tộc, khiến Nhị công tử và Lục công tử chết trận, còn lão tổ phải dùng Tổ Khí đưa người còn lại chạy thoát. Chương xác nhận cậu đã mở mười Động Thiên, nắm thần uy Chí Tôn, sau đó phá tiếp tịnh thổ Côn Tộc, Ly Tộc, Uyên Tộc và cướp sạch nhiều cổ giáo, làm cả Hư Thần Giới lẫn Hoang Vực chấn động. Ly Long tự tìm tới quyết chiến nhưng bị Nhóc Tỳ đánh bại, bắt lại và hầm thịt ăn. Hỏa Linh Nhi dẫn đại quân theo lệnh Hỏa Hoàng tới cứu cậu nhưng nổi giận vì bị gọi là bé mập mạp. Cuối chương, Thiếu nữ áo tím bí ẩn xuất hiện cùng một ông già bị sương mù bao phủ, và Nhóc Tỳ gọi nàng là Hung thú, đòi đưa về thôn."},{"chuong":221,"tieuDe":"Tôn Giả Thần Sơn","tomTat":"Thiếu nữ áo tím đối đầu Nhóc Tỳ nhưng bị hắn gọi là hung thú, khiến nàng tức giận vì nhớ lại nỗi nhục từng bị vật lộn ở Bách Đoạn Sơn. Nhóc Tỳ chủ động tấn công, một hơi tinh khí hóa kim quang mang phù văn đã phá được cốt văn bảo thuật của nàng, làm nàng nhận ra hắn đã mở Động Thiên thứ mười. Nàng dùng sừng thần và bông tai chí bảo để ngăn cận chiến, song vẫn bị Nhóc Tỳ đánh xuyên qua lớp phòng ngự. Tổ phụ của nàng ra tay, bộc lộ khí tức siêu phàm và sức mạnh chín Động Thiên, đồng thời muốn nói với Nhóc Tỳ về một hồi đại nhân quả, đại cơ duyên. Nhóc Tỳ không nghe, liên tiếp thi triển bảo thuật Côn Bằng và Toan Nghê, đánh lão già chật vật, thâm tím hai mắt, bốc khói và chỉ chăm chăm đòi đoạt bao tay thần binh. Lão tiết lộ bao tay là binh khí của Thần minh nhưng vẫn không dọa được Nhóc Tỳ; cuối cùng lão định bỏ đi rồi bị vật ngã, còn thiếu nữ áo tím xin thay tổ phụ ra tay và lại bị Nhóc Tỳ chộp tay định vật lộn."},{"chuong":222,"tieuDe":"Thập Hung Di Thuật","tomTat":"Nhóc Tỳ giao chiến với thiếu nữ áo tím và lão già đến từ Thái Cổ Thần Sơn, dùng phù văn cùng bảo thuật áp đảo đối thủ; thiếu nữ nhờ khuyên tai phát quang mới thoát khỏi thế bị trấn áp. Trong mảnh thiên địa này, Nhóc Tỳ mở cả mười Động Thiên, thần uy khiến quần hùng chấn động và nghi ngờ lai lịch của nó không đơn giản. Lão già ban đầu muốn trấn áp Nhóc Tỳ nhưng sau khi thấy mười Động Thiên thì đổi ý, tiết lộ tin tức tổ Thái Cổ Côn Bằng ở hoang vực giáp biển, nơi có thể ẩn giấu bảo thuật Thập Hung thất truyền. Nhóc Tỳ nghi ngờ đối phương dụ mình mở đường rồi hạ sát nên không dễ tin, dù lão già đề nghị dùng thượng cổ trớ chú phát thệ. Cuối cùng Nhóc Tỳ đặt điều kiện nhờ lão tìm phụ mẫu năm xưa đi Thái Cổ Thần Sơn hái thánh dược rồi mất tích. Sau đó nó cảm ơn Hỏa Linh Nhi, trở về Sơ Thủy Địa và mở thông đạo tới Hỗn Độn Phế Khư Địa để cầu viện Liễu Thần, vì chỉ tin Liễu Thần có thể chi viện khi bước vào cấm địa."},{"chuong":223,"tieuDe":"Thành Giao","tomTat":"Liễu Thần nghe Nhóc Tỳ kể lại mọi chuyện, phán đoán bảo thuật Côn Bằng nếu còn tồn tại thì sẽ nằm ở hải vực, nên khuyên nó đi tranh đoạt một lần dù chuyến đi rất nguy hiểm. Liễu Thần cũng chỉ ra rằng Nhóc Tỳ ở chốn thiên địa kia có thể trấn giết lão già, đồng thời khen việc tự mở mười Động Thiên là cực kỳ hiếm thấy và dặn sau khi trở về sẽ tẩy lễ cho nó. Nhóc Tỳ quay lại gặp lão già, liên tục mặc cả: muốn giải phù văn trong cơ thể Ly Long, đòi bảo thuật, rồi mượn được một chiếc bao tay bảo cụ để dùng trong chuyến ra hải ngoại. Nó còn âm thầm hiển hóa hình dáng một đôi nam nữ, yêu cầu lão già dò tin tức của họ và không được để lộ phong thanh, khiến lão phải thỏa hiệp. Khi lão già định rời đi, Nhóc Tỳ giữ Ly Long lại để đòi chuộc, cuối cùng hai Hoàng Kim Thú phải dùng một bộ cổ pháp thiên lôi không hoàn chỉnh đổi lấy thiếu chủ. Nửa tháng sau trở về Thạch Thôn, Nhóc Tỳ thấy Liễu Thần đang chuẩn bị trọng đại; Liễu Thần nói trời đất sắp loạn, lần này vừa tẩy lễ cho Nhóc Tỳ vừa tự lột xác, tiến thêm một bước và chữa trị thương thế, khiến Nhóc Tỳ càng nôn nóng muốn mạnh lên."},{"chuong":224,"tieuDe":"Cực Cảnh Tẩy Lễ","tomTat":"Thạch Hạo tiếp tục tự tôi luyện trong đại hoang, cứng chọi cứng với cự thú, hàng phục Thổ Hành Long thứ tám rồi kéo đi xa để không uy hiếp Thạch thôn. Hắn còn đối kháng thác nước, dùng phù văn khiến thác đảo chiều chảy ngược, qua đó ép thân thể, phù văn và tinh thần tới cực hạn. Sau hai đến ba tháng, Liễu Thần phát thần âm gọi hắn trở về để tẩy lễ; cả Thạch thôn kinh động khi hơn mười cành liễu rủ xuống như dây xích thần. Bốn bình ngọc vỡ, bảo huyết tứ đại hung thú bùng phát thần uy hủy diệt nhưng được Liễu Thần thuần hóa thành cam lộ trút lên người Thạch Hạo. Vì đã đạt cực cảnh Động Thiên, thân thể hắn mạnh thêm nhưng phù văn không biến hóa lớn, khiến hắn chủ động tìm cách phá giới hạn bằng mười Động Thiên. Tinh khí thần hóa thành Chân Long chia vào mười Động Thiên, rồi Liễu Thần tiếp tục buông thần tính tinh hoa của chính mình, tạo sinh mệnh khí cơ khiến cây cỏ hồi sinh và thôn dân được lợi. Cuối cùng Thạch Hạo cô đọng tinh thần nhập vào mười Động Thiên, dung hợp chúng thành một tiên vực và nhận ra hướng tiếp theo để tiếp tục đột phá."},{"chuong":225,"tieuDe":"Tái Diễn","tomTat":"Nhóc Tỳ đạt trạng thái tinh thần dung hợp với mười Động Thiên, như nhìn thấy quá trình khai thiên và cách sinh mệnh diễn biến, từ đó thu nhận nhiều ấn ký đại đạo. Nó thử dồn tinh khí thần của chín Động Thiên cùng chất lỏng của Liễu thần vào một Động Thiên để tái diễn sinh cơ, nhưng các điểm sáng và cỏ cây vừa thành lại nổ tung. Sau ba tháng bế tắc, nó nghi ngờ mười Động Thiên chưa hẳn là cực hạn và quyết định mạo hiểm tự hủy một Động Thiên để tìm đường vượt cấm kỵ. Liễu thần không ngăn cản, chỉ nói đây là con đường của nó, còn mọi người trong thôn đều hoảng sợ can ngăn. Nhóc Tỳ tập hợp sức mạnh chín Động Thiên oanh kích Động Thiên còn lại, khiến bản thân phun máu, trọng thương, nhưng nhờ thân thể gần như bất hủ và Liễu thần trấn giữ nên vẫn sống sót. Nó nhiều lần chữa thương rồi tái tạo, song Động Thiên liên tục nổ tung, thân thể rách nát đến lộ xương trắng. Trong lúc thất bại, nó nhìn thấy mảnh vỡ áo nghĩa đại đạo và ngộ ra pháp tắc trường tồn, cuối cùng tái tạo được một Động Thiên lớn ngang Động Thiên thứ mười. Sau một ngày một đêm, mười Động Thiên đều được xây dựng lại hoàn tất, dao động thần năng kinh người, và Nhóc Tỳ cảm thấy dường như có biến hóa mới."},{"chuong":226,"tieuDe":"Lại Biến Hóa","tomTat":"Dưới gốc cây liễu, Nhóc Tỳ mở ra mười Động Thiên viên mãn, mỗi Động Thiên rộng lớn như một mảnh Tiên Giới, khiến Liễu Thần, Nhị Ngốc Tử, Đại Hồng Điểu và người Thạch thôn đều chấn động. Hắn thử tiến thêm một bước bằng cách dung hợp mười Động Thiên thành một phương thiên địa, nhưng các Động Thiên va chạm phá hủy lẫn nhau, làm thân thể hắn chịu phản chấn và tràn máu. Trong lần suy diễn tiếp theo, Nhóc Tỳ nhận ra thân thể mình có thể bị Động Thiên phân giải, còn Liễu Thần chỉ ra đó là con đường tế sống chính mình, một thủ đoạn cấm kị thương tổn thiên hòa và dễ dẫn tới thiên khiển. Nhóc Tỳ từ đó hiểu được có thể lật ngược thủ đoạn này khi địch nhân dùng Động Thiên công kích, nhưng hắn cũng cảm thấy mình đã đến cực hạn Động Thiên cảnh theo lối cũ. Sau hai canh giờ bế tắc, hắn quyết định đánh cược lần cuối, dùng thần dịch còn dư, thiêu đốt sinh mệnh và vận chuyển Phù Văn tập trung nơi ngực. Mười Động Thiên dần sinh liên hệ, xoay quanh thân hắn và cuối cùng hóa thành một vòng thần hoàn to lớn, thần hà chiếu cửu thiên, để Nhóc Tỳ đứng ở trung tâm với khí thế bễ nghễ thế gian."},{"chuong":227,"tieuDe":"Thành Công Cực Điểm","tomTat":"Thạch Hạo hoàn thành con đường tự khai mở ở Động Thiên cảnh khi thập đại Động Thiên tương liên giao hòa, hóa thành một vòng thần hoàn bao phủ thân thể, khiến Liễu Thần, Nhị Ngốc Tử, Đại Hồng Điểu và người Thạch Thôn chấn động. Thần hoàn từng giải thể làm mọi người lo hắn thất bại, nhưng sau đó lại tái hợp, truyền thần lực tinh hoa vào thân thể và khiến Chí Tôn Cốt hấp thu một phần lực lượng rồi ngủ say. Đại Hồng Điểu nhận ra thần hoàn đang dưỡng thành trạng thái thân thể Động Thiên, nơi quang đoàn trong cơ thể Thạch Hạo có thể tẩm bổ ra bảo thuật độc nhất của bản thân. Liễu Thần kết thúc tẩy lễ, còn Thạch Hạo thừa nhận quá trình từng nguy hiểm đến gần hình thần câu diệt nhưng cuối cùng vượt qua. Sau đó dân Thạch Thôn ùa tới vui đùa, người lớn trêu hắn chuyện lấy vợ, gả Hổ Nữu và sinh hậu nhân khiến hắn xám xịt bỏ chạy. Liễu Thần cho biết hắn có thể vào Hư Thần Giới nhận ban thưởng vì quy tắc nơi đó đã biến hóa, rồi mở thông đạo bằng cành liễu; ba tháng sau Thạch Hạo tái xuất ở Hư Thần Giới, khiến các thế lực chú ý và Thái Cổ Thần Sơn chờ hắn tiến vào Hóa Linh cảnh để tìm Di Thuật Thập Hung ngoài hải ngoại."},{"chuong":228,"tieuDe":"Sơ Văn","tomTat":"Nhóc Tỳ trở lại Sơ Thủy Địa, lập tức khiến các đại giáo phái và những người từng chịu thiệt dưới tay nó hoảng sợ. Nó rời Sơ Thủy Địa qua thông đạo màu vàng, đến khu vực từng khai mở Động Thiên thứ mười và nhận thêm hai mảnh Thanh Đồng Thư do Hư Thần Giới ban thưởng, nâng tổng số lên năm khối. Một bia đá hiện ra khắc bốn chữ Động Thiên Chí Tôn, xác nhận nó là người mạnh nhất Động Thiên cảnh trong Hư Thần Giới ở Hoang Vực. Sau đó các đại biểu Thái Cổ Thần Sơn tìm tới, trong đó thiếu nữ áo tím báo rằng chín năm trước cha mẹ nó từng quanh quẩn gần Thái Cổ Thần Sơn rồi đã thoát khỏi Hoang Vực. Tin này khiến Nhóc Tỳ chấn động, mắt đỏ và trầm mặc hồi lâu, còn thiếu nữ áo tím cảnh báo đại chiến hải vực sắp bùng nổ nên nó cần sớm tiến vào Hóa Linh cảnh. Rời khỏi đó, Nhóc Tỳ đi qua những Tịnh Thổ cũ của Vũ Tộc và Thác Bạt Tộc, rồi tới Võ Vương Phủ vì cảm nhận cha mẹ từng đặt chân nơi này. Khi bị người canh gác nhận ra và ngăn lại, nó chỉ nói mình tới đây làm khách."},{"chuong":229,"tieuDe":"Võ Vương Phủ","tomTat":"Nhóc Tỳ xuất hiện trước sơn môn Võ Vương Phủ trong Hư Thần Giới, khiến người canh giữ căng thẳng vì danh tiếng sát tinh của hắn sau các trận quét ngang đại giáo, Vũ Tộc và Thác Bạt Tộc. Một trưởng lão trong phủ ra nghênh đón, dẫn hắn vào Tịnh Thổ, nơi có linh dược, linh sơn và cung điện tu luyện. Nhóc Tỳ dò hỏi quan hệ thông gia giữa Võ Vương Phủ và Vũ Tộc, rồi chuyển sang truy vấn tin tức Thạch Nghị, biết thêm việc Võ Vương đã xuất quan và có Chí Cường Giả hộ pháp cho Thạch Nghị khi mở Động Thiên thứ mười. Hắn đi tới Diễn Võ Trường, tìm dấu vết cha mình nhưng thấy riêng thế hệ Thạch Tử Lăng bị thiếu hụt, sau đó chạm vào kỷ lục bia của Thạch Nghị. Chí Tôn Cốt trong ngực Nhóc Tỳ phát sinh cảm ứng khiến tấm bia thiên thạch khắc chưởng ấn Thạch Nghị nổ tung chia năm xẻ bảy. Người Võ Vương Phủ lập tức kích hoạt cấm trận thượng cổ vây hắn ở trung tâm và gọi cường giả từ thế giới hiện thực sang. Cuối chương, tông lão Thạch Lạp xuất hiện chỉ trích Nhóc Tỳ, và hắn nhận ra đây chính là kẻ năm xưa từng bao che mẹ con Thạch Nghị, kêu người vây giết cha mình."},{"chuong":230,"tieuDe":"Đơn Giản Và Trực Tiếp","tomTat":"Thạch Lạp nghe tin Hùng Hài Tử đến Võ Vương Phủ liền chạy tới quan sát và nhanh chóng nảy sát ý, vì cho rằng thiếu niên này sẽ trở thành kình địch của Thạch Nghị. Bất chấp lời can gián của các trưởng lão, hắn vu cho Nhóc Tỳ xâm phạm tôn nghiêm vương hầu rồi phát động trận pháp Tế Linh Thượng Cổ do Tế Linh Thạch Quốc lưu lại. Nhóc Tỳ không né tránh mà mở mười tòa Động Thiên, để chúng giao hòa thành thần hoàn, che lấp tầm nhìn đối thủ và trực tiếp nghiền nát phù văn cùng trận văn dưới đất. Đại trận Thượng Cổ cạn thần lực, bị phá giải ngay trước mắt mọi người. Nhóc Tỳ nhận ra đám người theo Thạch Lạp là những kẻ thuộc một chi cũ từng bảo vệ mẹ con Thạch Nghị và vây công Thạch Tử Lăng năm xưa. Nó kéo Thạch Lạp về dưới chân, rút Diệt Hồn Châm rồi lại cất đi vì cho là lãng phí, đồng thời bộc lộ ý định ngày sau đến Võ Vương Phủ trong thế giới hiện thực để nói Thạch Hạo còn sống và đánh bại kẻ chiếm Chí Tôn Cốt. Cuối cùng Nhóc Tỳ đạp chết Thạch Lạp, rồi dùng phù văn màu vàng khiến toàn bộ nhân mã của hắn nổ tung thành sương máu."},{"chuong":231,"tieuDe":"Bố Trí Ổn Thỏa","tomTat":"Sau khi một cước đạp chết trưởng bối Thạch Lạp của Võ Vương Phủ trong Hư Thần Giới, Nhóc Tỳ rời tịnh thổ khiến con cháu Thạch Tộc kinh hãi lùi tránh, cường giả tới cứu viện cũng bị trưởng lão ngăn không cho la hét. Người Võ Vương Phủ hé lộ bí mật phong ba năm đó về một Chí Tôn trời sinh đã tàn lụi quá sớm, liên quan vợ chồng Thạch Tử Lăng mà phủ nợ lớn. Nhóc Tỳ trở về Thạch Thôn qua Liễu Thần ở phế tích Hỗn Độn, quyết tâm tu hành đợi tin Thần Sơn Thái Cổ để tìm bảo thuật Côn Bằng. Thạch Thôn sau mấy tháng biến hóa lớn thành vùng tịnh thổ nhờ linh dược, cây đào bạc và trứng thần của Bát Trân Kê. Do con của Đại Tráng gọi cậu bằng thúc thúc, Thạch Phi Giao và Thạch Lâm Hổ cùng tộc trưởng tán thành đổi cách gọi từ Nhóc Tỳ sang tên thật Thạch Hạo. Thạch Hạo diệt đám giặc cỏ cứu một thôn nhỏ cách hai ngàn dặm và phát hiện âm mưu Tiểu Tây Thiên thu thập hắc kim để mở bảo tàng Chí Tôn. Liễu Thần ở lại chờ một sinh linh quen thuộc, trao cành cây óng ánh làm phương tiện cứu viện. Cuối cùng Thạch Hạo đột phá Hóa Linh Cảnh ở tuổi mười một và đồng ý lên đường ra biển tìm bảo thuật Côn Bằng."},{"chuong":232,"tieuDe":"Thiên Thần Sơn","tomTat":"Sau khi thảo luận, Thạch Hạo quyết định ra biển cùng đám thần bộc tìm bảo thuật Côn Bằng, nhưng nhất quyết không tiết lộ vị trí Thạch Thôn vì đó là nơi ký gửi tâm linh tối trọng yếu. Nó cầu viện Liễu Thần, được thân cây cháy đen sảng khoái đáp ứng mở thông đạo dịch chuyển để khỏi lặn lội một hai năm. Cả thôn tiễn biệt lưu luyến, nhiều người rơi lệ; Đại Hồng Điểu muốn theo nhưng bị từ chối, Nhị Ngốc Tử lắc đầu không đi vì dường như có quan hệ ẩn với Thái Cổ Thần Sơn. Vào phút chót Mao Cầu hóa vệt kim quang nhảy lên vai đòi theo và được mang cùng, rồi Thạch Hạo vọt vào thông đạo biến mất. Nó xuất hiện ở vùng thần thổ linh khí đậm đặc, thấy Thái Cổ Thần Sơn chọc thủng mây xanh, và gặp lại thần bộc Hoàng Kim Thú từng bị nó đánh bại ở Hư Thần Giới. Thần bộc dùng uy thế áp nhưng bị mười Động Thiên ngăn, buộc phải cầu cạnh Thạch Hạo mở thông đạo cấm kỵ Côn Bằng, còn tỏa bảo quang tạo cầu thần dẫn đường và hứa tặng bát trân Thái Cổ. Thạch Hạo lao ra định bắt Bát Trân Kê thì bị ngăn, rồi xung đột với thiếu niên tóc xanh khiến nhóm thiếu niên thiếu nữ các thế lực xuất hiện; thiếu nữ áo tím Vân Hi ngăn cản, còn Thạch Hạo thì thầm chê các thiếu nữ mập khiến thiếu nữ tóc bạc Ngân Tuyết hỏi lại và Vân Hi tức giận."},{"chuong":233,"tieuDe":"Xung Đột Và Cường Thế","tomTat":"Thạch Hạo đối đáp trêu chọc nhóm thiếu nữ Thần Sơn, buột miệng chê các nàng mập vì tẩm bổ linh dược nhiều, rồi nhắc lại chuyện từng đánh nhau lăn lộn với thiếu nữ áo tím ở Bách Đoạn Sơn khiến nàng ngại mất mặt. Thiếu niên tóc xanh cảnh cáo về quy tắc Thái Cổ Thần Sơn, bị Thạch Hạo phản bác rằng chính họ cầu cạnh mời hắn tới nên phải kính nể hắn. Thiếu niên tóc dài màu tím đứng ra hòa giải, nhấn mạnh cần đồng tâm hiệp lực để đoạt bảo thuật Côn Bằng khi vào Hải Vực. Nhóm người lên Thiên Thần Sơn cảnh sắc như tiên cảnh, Nhóc Tỳ ngắt linh dược khe núi cho Mao Cầu ăn. Trước Thiên Cung, liên minh các thế lực bàn kế hoạch thu hoạch trong Hải Vực, dùng các thiếu niên Hóa Linh Cảnh làm chủ lực. Có người nghi ngờ Thạch Hạo quá yếu, một thiếu niên mười sáu mười bảy tuổi đã vào Hóa Linh Cảnh hai năm đứng lên thử sức. Thạch Hạo nổi giận, mở đồng thời mười Động Thiên thành vòng thần hoàn nghiền nát tiên hạc rồi một chưởng chia thây đối thủ, khiến cả Thần Sơn khiếp sợ; thiếu niên tóc xanh định động thủ thì một ông lão cao cao tại thượng lên tiếng can ngăn."},{"chuong":234,"tieuDe":"Bắc Hải","tomTat":"Nhóm Chí Cường Giả ngồi trước thiên cung cười xòa hóa giải vụ Thạch Hạo giết người trên Thần Sơn, coi như chuyện nhỏ. Họ cho biết vì đã vượt Hóa Linh Cảnh nên không vào được hang ổ Côn Bằng, có ước hẹn không ra tay mà giao cho hậu bối tranh đoạt bảo thuật Côn Bằng. Tổ phụ thiếu nữ áo tím mở thông đạo năm màu; bị Thạch Hạo trêu tức nên thổi cuồng phong đẩy nó vào, chỉ thét được ba chữ Hùng Hài Tử. Đại quân sáu bảy trăm người xuất hiện ngoài biển cách Thần Sơn mấy trăm vạn dặm — đây là Bắc Hải, cực Bắc của Hoang Vực, khiến Thạch Hạo lần đầu thấy biển mà chấn động. Lão bộc dùng bảo thuyền hạt cây vượt biển nhưng bị quái ngư bạc phóng lôi đình đánh nổ, tử thương hơn nửa; thần bộc dùng da thú che chở và trấn áp quái ngư đến trọng thương. Đoàn tiếp tục bị đàn Hải Ma mấy vạn con và đại trận phong cấm dưới đáy biển vây, phải thổi cổ bảo Thần Sơn phá phù văn mở đường trốn. Cuối cùng gặp Thánh Giả không đầu thời Thượng Cổ cưỡi ngựa đen cầm chiến mâu vàng chém tan da thú, thần bộc nhận ra không thể chống lại và nghi đoàn đã tới Ma Hải gần cổ sào Côn Bằng; Thạch Hạo chấn động thấy cường giả trong biển còn nguy hiểm hơn cả Đại Hoang."},{"chuong":235,"tieuDe":"Vùng Đất Tử Vong","tomTat":"Đoàn hơn ba trăm sinh linh từ Thần Sơn Thái Cổ trên đường tới sào huyệt Côn Bằng bị một Thánh Giả không đầu Thượng Cổ — kỵ sĩ cưỡi ngựa đen cầm chiến mâu vàng óng — thảm sát, chỉ cần chiến mâu quẹt qua là nổ tung. Vài thần bộc thổi sừng thú chí bảo tạo gợn sóng bạc mới tránh được kiếp nạn, còn Thạch Hạo (Hùng Hài Tử) nhận ra kỵ sĩ chỉ có chiến ý không ý thức nên dùng Long Giao Tiễn thoát ly chiến trường. Hơn ba trăm người chỉ còn hơn năm mươi, trong đó có Ngân Tuyết, Xích Hỏa và Thanh Vân, tất cả quyết đoạt bảo thuật Côn Bằng — thần thông cái thế của Thập Hung. Đoàn vượt phong cấm của Giao tôn giả, đánh tan hơn vạn cá mập bạc để tiến vào vùng biển tử vong nơi di địa Côn Bằng chồng lên chiến trường Thượng Cổ. Càng vào sâu tu vi càng bị áp chế bất ổn, thần bộc suy diễn phong ấn thần sào Côn Bằng đang mở và có thể xuất thế hoàn toàn — điều khiến Thạch Hạo cảm thấy bất lợi cho mình. Khi phát hiện mảnh vỡ chiến thuyền Nam Vẫn Thần Sơn và các U Linh Thuyền lạc từ Thượng Cổ, một quái vật xúc tu khổng lồ tấn công; cánh Côn Bằng của Thạch Hạo tự bùng phát cứu nó nhưng nó bị đoàn bỏ mặc, chìm vào biển sâu rồi cuối cùng đạp nước xông thẳng lên một chiếc U Linh Thuyền."},{"chuong":236,"tieuDe":"Câu Đố Còn Sót Lại Từ Thượng Cổ","tomTat":"Bị con bạch tuộc khổng lồ tám tua truy kích, Thạch Hạo buộc phải leo lên U Linh Thuyền — thứ đại biểu cho cái chết — để giữ mạng, trong khi bạch tuộc quay sang cướp luyện chiếc sừng thú chở nhóm thần bộc. Sừng thú phát sáng chặt đứt tua bạch tuộc rồi bay lên trời thoát vùng biển tử vong, nhưng chấn động khiến hơn mười mấy người rớt xuống bị xúc tu tiêu hóa cả xương. Dù thiếu nữ áo tím và Ngân Tuyết đòi cứu Thạch Hạo, Thạch Vân vẫn cười lạnh ném khối xương thú nổ tung vào thuyền rồi cả nhóm bỏ đi. Khoang thuyền tỏa sáng đen giam giữ Thạch Hạo và Bóng Lông, hút tinh khí; hắn vận kiếm gãy khiến vết máu đen trên thân hóa đỏ tươi như thức tỉnh, điên cuồng nuốt sức mạnh U Linh Thuyền và giải phóng cả hai. Thuyền tan rã thu nhỏ còn hơn một trượng, lộ chân tướng là thuyền giấy màu đen khắc dòng chữ Chỉ còn sót lại chính ta thôi cùng dấu vân tay máu của một cô gái Thượng Cổ. Thạch Hạo thu phục thêm một U Linh Thuyền thứ hai làm lá chắn rồi tiến sâu vào biển cấm, cuối cùng thấy hòn đảo tổ chim khổng lồ hơn Ma Sơn Thái Cổ với từng tia Hỗn Độn Khí buông xuống."},{"chuong":237,"tieuDe":"Máu Nhuộm Biển Xanh","tomTat":"Hang ổ Côn Bằng của Thập Hung Thái Cổ xuất hiện trên biển, kéo tinh anh các tộc và nhiều cường giả tới tranh đoạt bảo thuật vô thượng, khiến mặt biển nhuộm đỏ máu. Chim loan xanh và Thiểm Điện Khuyển đại chiến vì thù con cháu, nhưng cả hai trọng thương rồi bị đàn Hải Ma vây giết giữa vùng biển bị gợn sóng cấm kỵ áp chế tu vi. Cửu Linh Vương và các cường giả khác phản kích, song sự nguy hiểm của biển cấm khiến nhiều kẻ phải rút lui. Giao tôn giả hiện thân như dãy núi xám, Thôn Thiên Tước cũng lộ diện chưa chết, rồi bị Hôi Giao đánh để tranh độc chiếm bảo thuật. Khi vách đá cổ phát ra gợn sóng vàng áp chế, Thôn Thiên Tước và Hôi Giao đều rời đi, còn Thạch Hạo nhận ra Hoang Vực sắp bước vào đại loạn. Sau nhiều ngày chém giết, con đường đá mênh mông dẫn tới vùng đất cổ Côn Bằng hiện ra trên biển. Thạch Hạo chờ áp chế hoàn toàn hình thành rồi bỏ U Linh Thuyền, bước lên thềm đá tiến vào đảo. Gần vùng đất cổ, hắn chạm mặt nhóm liên minh Thiên Thần Sơn gồm Vân Hi, Ngân Tuyết, Xích Hỏa, Thanh Vân và thần bộc, những kẻ từng đẩy hắn vào chỗ chết."},{"chuong":238,"tieuDe":"Xé Đôi","tomTat":"Sau khi sống sót thoát khỏi U Linh Thuyền, Thạch Hạo tái ngộ nhóm thiếu nữ áo tím Vân Hi và Ngân Tuyết muốn lôi kéo hợp tác trở lại, nhưng hắn tuyên bố chỉ hứng thú với thuần huyết của Thanh Vân và muốn giết. Thanh Vân kiêu ngạo ra lệnh cho lão bộc di chủng bắt người, đồng thời tiết lộ tin đồn sào huyệt Côn Bằng tự động mở ra không cần thủ đoạn đặc biệt. Lão bộc hóa Toan Nghê tấn công bằng lôi hải, nhưng Thạch Hạo áp sát nhờ đôi cánh Côn Bằng, kéo gãy cánh tay và phá xương cốt, dùng phù văn Nguyên Thủy Chân Giải hóa giải cốt văn nên không bị thương. Thanh Vân là sinh linh thuần huyết mở chín Động Thiên, hóa thành chim Thanh Loan thi triển vạn kiếm và thần thông thiên phú hai dải ngân hà giam cầm cố định Thạch Hạo. Thạch Hạo bùng phát mười tòa Động Thiên cùng xuất hiện nối liền thành vòng thần hoàn bất hủ ẩn thần lực Hóa Linh, phá tan hai dải ngân hà thoát giam cầm khiến mọi người kinh ngạc. Cuối cùng hắn bắt cổ chân Thanh Vân đập xuống thềm đá di tích Thượng Cổ làm biến dạng mặt, rồi ôm chân đạp kéo xé rách hai chân hắn hơn phân nửa."},{"chuong":239,"tieuDe":"Hang Ổ Thật Sự","tomTat":"Thạch Hạo trong trạng thái Hóa Linh Cảnh với Mười Động Thiên dung hợp đánh Thanh Vân trọng thương, khiến xương cốt đối thủ đứt gãy nghiêm trọng, nhưng phù văn của đám thần bộc bảo vệ Thanh Vân nên hắn không chết. Khi thần bộc định bắt Thạch Hạo, đàn Hỏa Viêm Ngư trong truyền thuyết bất ngờ xuất hiện như dòng lũ lửa, làm hỗn loạn thềm đá và giúp Thạch Hạo thoát khỏi nguy cơ. Thanh Vân vừa đau đớn vừa uất hận, thề sau khi hồi phục sẽ tự tay giết Thạch Hạo, còn Thạch Hạo chế nhạo hắn đã không còn hy vọng nếu không có người cứu. Sau nhiều ngày leo lên đỉnh đảo, Thạch Hạo phát hiện hang ổ Côn Bằng ở đó đã biến mất, chỉ còn Hỗn Độn Khí và một tòa trận pháp truyền tống Thái Cổ. Cổ trận đưa mọi người rời xa bảy tám mươi vạn dặm tới vùng đất cổ có linh khí Tiên Thiên đậm đặc, nơi hang ổ thật của Côn Bằng nằm trên rặng đá ngầm giữa biển. Sinh linh các phương chém giết đẫm máu để tranh đường vào, trong đó một hậu nhân Hải Thần mặc chiến y vàng dùng Tam Xoa Kích giết sạch đám người cãi lời. Cuối chương, Thạch Hạo chú ý tới cánh cửa vàng rực rỡ như nối liền Thần Giới và kinh ngạc khi thấy một chiếc thuyền giấy màu đen trôi ra từ bên trong."},{"chuong":240,"tieuDe":"Phiêu Lưu Vạn Cổ","tomTat":"Thạch Hạo thu lấy một chiếc thuyền giấy màu đen trôi trên dòng sông linh dịch, nghi ngờ nó liên quan đến hình dáng nguyên thủy của U Linh Thuyền. Trên thuyền có dòng chữ máu “Chỉ còn lại mỗi mình ta”, vết máu vẫn đỏ tươi và ẩn chứa thần năng mênh mông, khiến hắn cảm nhận cảnh tượng nhật nguyệt tinh hà đảo lộn như đến từ vạn cổ. Ngay sau đó, quần hùng phát hiện Côn Mộc trong cánh cửa cấm kỵ, gồm một khúc gỗ mục có long văn, thánh huy cùng chiếc lá trong suốt không mục nát, làm vô số sinh linh điên cuồng lao vào tranh đoạt. Dòng sông trước cửa lại là vùng cấm đáng sợ, bất kỳ ai bước vào đều nổ tung thành tro bụi, kể cả sinh linh biển khổng lồ. Hậu nhân Hải Thần xuất hiện trong chiến y hoàng kim, dùng sóng biển vàng và chiến kích quét ngang, nghiền nát nhiều cường giả để uy hiếp quần hùng. Khi thuộc hạ Hải Tộc khiêu khích và định đạp vào ngực Thạch Hạo, hắn dùng kiếm gãy màu đen chém đôi đối phương. Hậu nhân Hải Thần tức giận chỉ kích về phía hắn, còn Thạch Hạo đáp trả rằng dù là Hải Thần nếu dám trêu chọc hắn cũng chỉ có con đường chết."},{"chuong":241,"tieuDe":"Hậu Nhân Hải Thần","tomTat":"Hậu nhân Hải Thần xuất hiện với chiến kích màu vàng, ép Thạch Hạo giao chiến để báo thù cho người hầu bị giết, khí thế được xưng như Hải Thần thiếu niên tái thế. Thạch Hạo vận dụng mười Động Thiên nối thành vòng thần hoàn, tạo sức giam cầm kinh người rồi dùng kiếm gãy chém xuống, nhưng đối thủ vẫn phá thế mà đứng vững, khiến quần hùng chấn động. Khi hai bên đang đối đầu, một thiếu niên tóc đỏ do Hỏa Viêm Ngư hóa hình lao tới, cầm chiến mâu màu máu tấn công hậu nhân Hải Thần, khơi lại mối thù xưa giữa tộc Hỏa Viêm Ngư và Hải Thần nhất mạch. Hai cường giả trẻ tuổi giao chiến dữ dội, còn Thạch Hạo nhân cơ hội rút khỏi vòng xoáy, chạy về phía hang ổ Côn Bằng, đồng thời cảm nhận cốt văn màu vàng trong cơ thể sôi trào bất thường khiến nó sinh cảnh giác. Tại hang ổ Côn Bằng, các cường giả lục địa dùng một mảnh tàn cốt Côn Bằng để phá phong ấn lối vào, khiến sương mù hỗn độn tràn ra và đạo trường cổ xưa rung chuyển. Lối vào vừa hé mở, quần hùng lập tức đồng loạt xông lên tranh đoạt bảo thuật, còn Thạch Hạo chạy tới chứng kiến cảnh hỗn loạn ấy thì nhíu mày vì cục diện đã biến đổi quá nhanh và quá khó lường."},{"chuong":242,"tieuDe":"Hỗn Chiến","tomTat":"Trước cổ sào Côn Bằng, quần hùng từ nhiều chủng tộc lao vào chém giết để tranh đoạt bảo thuật, thi thể chất đống và máu chảy thành sông. Thạch Hạo lẫn trong đám đông tiến sát lối vào, bị một hải thú trắng bạc cầm búa lớn ngăn cản nhưng dùng kiếm gãy chém đứt đôi cây búa rồi lọt vào trong. Bên trong là đạo tràng thời Thái Cổ rộng lớn, tự thành một giới, nơi tu vi vượt Hóa Linh bị áp chế và có tảng đá khắc huyền cơ về Côn Bằng. Tử Tinh Ngư xuất hiện với Tử Tinh Kiếm, phun khí tím hóa thành vầng mặt trời tím càn quét cường giả, phá hủy bức tranh trên tảng đá rồi hút đá vụn. Thanh Vân thương thế đã khỏi, cầm kim tiên truy sát Hùng Hài Tử để rửa nhục, nhưng bị Thạch Hạo nhắc lại chuyện từng bị xé hai chân khiến thế công rối loạn. Thần bộc Thái Cổ Thần Sơn dùng sừng thú chí bảo tạo sóng bạc trói ánh kiếm, rồi giao chiến khiến Thạch Hạo dù hiện thập đại Động Thiên vẫn bị chấn lùi vì tu vi còn thấp. Khi có tiếng hô đã tới phần cuối, toàn bộ hỗn chiến tạm dừng, mọi người chen lấn lao về phía trước."},{"chuong":243,"tieuDe":"Tỉnh Ngộ","tomTat":"Con đường duy nhất vào trung tâm hang ổ Côn Bằng bị một đôi cửa đá khổng lồ và cổ mộc ngăn lại, khiến quần hùng nhận ra đây mới là lối vào chân chính. Hải Kình, Bạo Viên bạc cùng nhiều sinh linh thử phá cửa, nhưng phù văn trên cửa đá bùng nổ thành đại sát kiếp, giết chết tối thiểu ba phần mười người có mặt; Thạch Hạo nhờ kiếm gãy hộ thể nên chỉ bị chấn thương, không nguy hiểm tính mạng. Sau đó các thế lực gộp máu, cốt, vảy và lông Côn Bằng, khiến cửa đá chấp thuận mở ra, để mọi người tràn vào đạo tràng đầy linh dược và bảo dược. Dù bảo địa hấp dẫn, phần lớn cường giả vẫn tiếp tục tiến sâu vì bảo thuật Côn Bằng còn ở nơi xa hơn, còn hành trình kéo dài hơn một tháng vẫn chưa tới điểm cuối. Thạch Hạo trong quá trình ấy nhận ra chấp niệm tranh đoạt bảo thuật đã khiến đạo tâm bất ổn và bản thân liên tục lao vào đại chiến nguy hiểm. Cậu quyết định dừng tranh cướp, chọn tĩnh tâm tu luyện trên cổ mộc trong hang ổ; khi ngộ pháp, mười Động Thiên hiện lên, hai tòa Côn Bằng và Toan Nghê tỏa khí lành, biểu hiện sự lột xác ở Hóa Linh Cảnh."},{"chuong":244,"tieuDe":"Thân Thể Thành Linh","tomTat":"Thạch Hạo ngồi ngộ đạo trong Hóa Linh Cảnh tại hang ổ Côn Bằng, xương trán phát sáng, thần thức căng trào, thân thể dần hóa linh từ huyết nhục đến xương cốt. Những thương thế do các trận đại chiến trước đó được chữa lành, lục phủ ngũ tạng trở nên óng ánh, khí tức tăng mạnh qua quá trình thôn hà thổ tụy. Chương giải thích thân thể thành linh là bước lớn đầu tiên và là căn cơ quan trọng nhất của Hóa Linh Cảnh, trước khi tinh thần đắp nặn chân ngã và dưỡng linh với thập đại Động Thiên. Mao Cầu tỉnh lại sau lột xác, ăn rất nhiều linh dược trong vùng đất cấm và kéo về tám tấm bia đá Côn Bằng ghi tiểu sử khổ tu của Côn Bằng. Thạch Hạo cùng Mao Cầu rời hang ổ, trong khi nhiều thế lực bên ngoài đã lui dần vì tử thương mà không tìm ra bảo thuật. Sau đó Thạch Hạo xuống biển, lần lượt mài giũa thân thể tại động Cực Dương, vực Huyền Băng và mộ Vẫn Tinh. Gần ba tháng sau, ở đáy biển tối tăm, nó mở mắt bắn ra điện thần và xác nhận thân thể thành linh đã thành công."},{"chuong":245,"tieuDe":"Con Đường Chân Chính","tomTat":"Sau ba tháng mài giũa dưới đáy biển, Thạch Hạo đạt tới thân thể thành Linh, toàn thân lột xác tới cực điểm và bước vào trạng thái trong ngoài như một. Nó dựa vào Nguyên Thủy Chân Giải do Liễu Thần từng mang tới Thạch Thôn để tổ hợp phù văn trong cơ thể, khiến giai đoạn Hóa Linh Cảnh này viên mãn và chiến lực tăng vọt. Khi trở lên mặt biển, Thạch Hạo thấy vùng gần hang ổ Côn Bằng vẫn tranh đoạt dữ dội, nhiều tu sĩ và cường giả ẩn thân tụ tập. Nó phát hiện hang ổ Côn Bằng phóng ra phù văn nguyên thủy không trọn vẹn, từ đó ngộ ra con đường vô hình dẫn tới bảo thuật Côn Bằng chỉ dành cho người đi đúng con đường tu hành ấy. Trong nửa tháng tiếp theo, mỗi ngày nó đều thu hoạch pháp môn đơn giản từ biến hóa phù văn, dù chưa nắm được bảo thuật chân chính. Cuối chương, Thanh Vân dẫn cao thủ vây Thạch Hạo; Thạch Hạo không còn nhẫn nhịn, quyết định lấy sinh linh thuần huyết này làm đối tượng thử sức sau khi thân thể thành Linh."},{"chuong":246,"tieuDe":"Vô Đề","tomTat":"Thanh Vân, người kế thừa Thái Cổ Thần Sơn, nổi giận vì từng bị Thạch Hạo làm nhục và đích thân cầm kim tiên tiến lên đối phó. Thạch Hạo không né tránh, tay không đón đánh, dùng lực lượng Toan Nghê và thân thể cường hoành liên tục nện đến mức kim tiên cong vẹo rồi vỡ tung, khiến các thần bộc nghi hắn đã đạt trạng thái Thân thể thành linh. Thanh Vân hóa bản thể Thanh Loan, dùng phù văn xanh như sao lớn công kích nhưng vẫn bị Thạch Hạo luyện hóa và áp chế. Khi tứ đại thần bộc chia bốn hướng đánh úp, Đả Thần Thạch và Kiến gãy cùng xuất hiện, còn Thập đại Động Thiên của Thạch Hạo liên kết thành thần hoàn chấn Thanh Loan phun máu. Thạch Hạo cưỡi lên lưng Thanh Loan, bẻ gãy cổ giết chết Thanh Vân bất chấp lời khuyên nể mặt Thái Cổ Thần Sơn; sức mạnh cấm kỵ trong thân Thanh Loan tự hủy, làm hắn không đoạt được bảo thuật bộ tộc. Vân Hi và Ngân Tuyết chứng kiến cảnh này trong kinh hãi, còn Thạch Hạo thu xác Thanh Loan rồi rời xuống biển sâu. Sau đó hắn lấy U Linh Thuyền làm thuyền ngắm biển, ăn thịt Thanh Loan, uống rượu Hầu Nhi với Mao Cầu, rồi gặp một mỹ nhân bí ẩn đạp sóng lên thuyền để kết thiện duyên."},{"chuong":247,"tieuDe":"Đối Thủ Xinh Đẹp","tomTat":"Trên U Linh Thuyền, Thạch Hạo gặp một thiếu nữ áo đen cực kỳ xinh đẹp âm thầm bước lên thuyền, khiến hắn lần đầu không nhìn thấu đối phương và lập tức cảnh giác. Nàng lấy Túi Càn Khôn tinh xảo ra bày rượu thịt, vừa tự nhiên đòi uống rượu vừa lộ ý cướp đoạt, còn Thạch Hạo cũng nảy ý cướp túi của nàng. Khi Thạch Hạo vận Thập đại Động Thiên thành thần hoàn ép tới, thiếu nữ hóa thành màn mưa ánh sáng rồi hợp lại, làm hắn và Mao Cầu kinh ngạc. Sau đó hai người cùng ăn thịt Thanh Loan thuần huyết và uống Hầu Nhi Tửu đến nửa đêm; thiếu nữ ăn còn nhanh hơn Thạch Hạo, trong khi hắn nhân dịp vừa đột phá để củng cố cảnh giới. Thiếu nữ tiết lộ mình không phải người Hoang Vực, đến vì Côn Bằng nhưng thấy độ khó quá lớn nên muốn trộm cắp trước, đồng thời cảnh báo Hoang Vực sau này sẽ rất loạn. Cuối chương, hai người bàn kế đánh lén các cường giả như người của Thần Sơn, hậu nhân Hải Thần và thiếu niên Hỏa Viêm Ngư, rồi quyết định bắt đầu một trận Thánh Chiến cướp bóc."},{"chuong":248,"tieuDe":"Thánh Chiến","tomTat":"Thạch Hạo cùng thiếu nữ đạp biển tiến về hang ổ Côn Bằng, ban đầu bàn chuyện cướp Tam Xoa Kích của hậu nhân Hải Thần và viêm trấp thần tính của bộ tộc Hỏa Viêm Ngư. Khi phát hiện Hải Tộc dựng tế đàn lớn đối diện rặng đá ngầm để hậu nhân Hải Thần cảm ngộ bí pháp Côn Bằng, thiếu nữ đổi mục tiêu sang đoạt Côn Bằng pháp trong đầu hắn bằng cổ pháp đọc tâm tư. Nàng nhận ra Đả Thần Thạch trên tóc Thạch Hạo, truyền cho hắn thần chú khống chế khiến Đả Thần Thạch phải nghe lời và tăng uy lực. Sau mấy ngày chờ đợi, Thạch Hạo trà trộn vào đám cu li, dùng Đả Thần Thạch nện trúng trán hậu nhân Hải Thần; thiếu nữ nhân cơ hội thi triển cổ pháp nhưng thất bại vì đối phương quá mạnh. Dù không đọc được tâm tư, hai người vẫn lấy được tàn cốt Côn Bằng và miếng vảy, còn hậu nhân Hải Thần sau khi tỉnh lại bạo nộ chém giết các kẻ hôi của. Thiếu nữ tiết lộ thân thể hiện tại chỉ là Linh Thân được nuôi dưỡng từ một Động Thiên, chân thân đang vướng chuyện nên khó vào Hoang Vực. Hai người tiếp tục nhiều ngày cướp bóc cường giả vùng biển bằng Đả Thần Thạch, thậm chí suýt thất thủ trước lão giao màu xám nghi là Linh Thân của Tôn Giả. Cuối cùng thiếu nữ rời đi vì tinh lực phân tán sẽ nguy hiểm cho chân thân, Thạch Hạo hẹn sau này cùng đi Thái Cổ Thần Sơn và Hải Thần Đảo, rồi thời gian lướt qua hai năm."},{"chuong":249,"tieuDe":"Đắp Lại Chân Ngã","tomTat":"Hai năm sau biến cố ở vùng biển Côn Bằng, quần hùng vẫn ra vào tranh đoạt, vô số sinh linh chết trận nhưng thần sào và bảo thuật chân kinh Côn Bằng vẫn chưa ai phá được. Chuyện Giao Tôn Giả bị hai tên trộm cướp sạch truyền ra ngoài, khiến hắn mất mặt và sai con cháu Giao Tộc lùng bắt, trong khi Thạch Hạo còn bí mật đánh mười tám cháu trai của hắn để cảnh cáo. Thạch Hạo lúc này hơn mười ba tuổi, thân mang mười Động Thiên và đã tu tới đỉnh cao Hóa Linh Cảnh, vượt xa nhiều thiên tài thuần huyết như Thanh Vân. Hắn ngồi dưới đáy biển trong Động Cực Dương, dùng chân hỏa dương cương cực điểm thiêu luyện thân thể và tinh thần nguyên, khiến da thịt nhiều lần cháy đen rồi tái sinh. Sau đó hắn chuyển sang Vực Huyền Băng, chịu chí hàn làm tinh thần nguyên đông kết, vỡ tan rồi khôi phục, luân phiên giữa hai cực dương và hàn. Cuối cùng Thạch Hạo hoàn thành giai đoạn Đắp lại chân ngã trong Hóa Linh Cảnh tới viên mãn, cạnh thân hiện lên Côn Bằng và Toan Nghê rít gào cộng hưởng như có linh tính."},{"chuong":250,"tieuDe":"Xuất Quan","tomTat":"Thạch Hạo bế quan trong động Cực Dương suốt hai năm, tinh thần sung mãn và lần lượt đẩy Thân thể thành linh cùng Đắp lại chân ngã tới ranh giới trong truyền thuyết, khiến chiến lực tăng vọt. Nó thử tiếp cận bệ đá cấm địa sâu trong động nhưng bị chân hỏa đánh thẳng vào linh hồn, nhận ra mình còn thiếu Hóa Linh Cảnh vô khuyết viên mãn mới có thể đặt chân lên đó. Khi xuất quan, nó biết vùng biển đã biến động dữ dội: nhiều đại nhân vật Hóa Linh Cảnh chết, Tôn Giả xuất thế, các thế lực Hải Tộc và Thần Sơn đều tụ lại. Mạc Thương, hậu nhân Hải Thần, đánh bại Nhân Ngư Tộc và muốn đoạt bảo thuật Côn Bằng để phong Thần, trong khi Hàn Thiên của bộ tộc Hỏa Viêm Ngư cũng là một đối thủ lớn từng cùng hắn lưỡng bại câu thương. Hang ổ Côn Bằng bắt đầu nứt ra, phù văn hiện lên trên rặng đá ngầm, Thạch Hạo đọc được một đám ký hiệu thần bí nhưng chưa rõ ý nghĩa. Khi nó tiến về phía hang ổ, quần hùng nhận ra tên trộm năm xưa; Mạc Thương, Thái Cổ Thần Sơn và Giao Tôn Giả đều lộ địch ý, còn Thạch Hạo thẳng thừng cảnh cáo rằng ai chọc nó sẽ bị ăn sạch."},{"chuong":251,"tieuDe":"Chiến Quần Hùng","tomTat":"Thạch Hạo xuất hiện trước quần hùng với dáng vẻ ngang ngược, lớn tiếng cảnh cáo ai dám trêu chọc sẽ bị ăn sạch, khiến những người từng biết hắn ở Bách Đoạn Sơn và Hư Thần Giới, nhất là Vân Hi, vừa lo lắng vừa kinh ngạc vì nhận ra hắn đã lại đột phá. Khi đám Hải Tộc không biết uy danh hắn mà xông lên, Thạch Hạo chỉ điểm Hải Giao, Ngân Sa Vương, Đại Hải Quy như chọn nguyên liệu, rồi dùng vòng xoáy vàng cuốn các sinh linh mạnh nhất, xuyên thủng mi tâm và thu xác vào Túi Càn Khôn. Mạc Thương, hậu nhân Hải Thần đang thủ trên tế đàn, vung chiến kích tạo cơn lũ vàng nhằm trấn áp nhưng bị Thạch Hạo một quyền phá tan, song hắn vẫn không rời tế đàn vì lo bị điệu hổ ly sơn khỏi lô cốt chiến tranh. Tiếp đó huynh trưởng của Thanh Vân, cường giả trẻ Thái Cổ Thần Sơn và sinh linh thuần huyết, đứng ra đòi mạng Thạch Hạo vì đệ đệ bị giết; lão bộc Thái Cổ Di Chủng xin thay chủ xuất thủ. Thạch Hạo thi triển bảo thuật tự diễn biến, sau lưng hiện đại dương đen và cá lớn do phù văn thai nghén, bị người ngoài nhầm là bảo thuật Côn Bằng nhưng được Tôn Giả nhận ra là khác biệt. Lão bộc bị chấn bay, hóa bản thể vàng lớn như núi liều mạng nhưng tiếp tục bị con cá đen đánh trọng thương gần tắt thở; Thạch Hạo không truy sát, chỉ cảnh cáo đừng chọc vào mình rồi nhìn sang thiếu niên tóc xanh, Mạc Thương và Giao Tôn Giả, khiến cả hải vực lặng đi vì chấn động."},{"chuong":252,"tieuDe":"Thiếu Niên Thiên Kiêu","tomTat":"Trên hải vực, Thạch Hạo bị một nam tử tóc xanh nhất mạch Thanh Loan khiêu chiến. Đối phương là sinh linh thuần huyết của Thái Cổ Thần Sơn, đã mở chín Động Thiên và thi triển thần thông Thanh Loan, nhưng bị Thạch Hạo dùng bảo thuật Toan Nghê diễn hóa lôi hải cùng hai cối xay màu vàng áp chế. Khi nam tử tóc xanh xuất linh thân và nhiều sinh linh thái cổ từ Động Thiên, Thạch Hạo mở mười Động Thiên, hợp thành thần hoàn như thần dương để giam cầm đối thủ, khiến Hải Tộc kinh sợ. Nam tử tóc xanh hóa thành Thanh Loan thoát ra, nhưng Côn Bằng từ Động Thiên Thạch Hạo bay lên chém rơi một cánh, còn Thạch Hạo dùng Túi Càn Khôn thu cánh ấy như nguyên liệu ăn uống. Sau đó Thạch Hạo nhận ra lão giả tóc xám áo bào xám ngoài xa rất có thể là chân thân Giao Tôn Giả, người từng bị nó và ma nữ cướp sạch. Tại tế đàn, Thạch Hạo khiêu khích Mạc Thương, hậu nhân Hải Thần, bằng cách hỏi bản thể hắn ăn có ngon không, rồi hai thiếu niên thiên kiêu quyết chiến ngang tài bằng nhục thân và phù văn. Giữa trận, Côn Bằng Sào trên đảo đá ngầm phát sáng vàng kim, nứt toác dữ dội và sắp hoàn toàn chia năm xẻ bảy."},{"chuong":253,"tieuDe":"Đại Quyết Chiến","tomTat":"Sào huyệt Côn Bằng màu đen khổng lồ mở ra, toàn thân tỏa vàng kim và gây chấn động cả hải vực. Quần hùng, kể cả những người vốn đứng xa quan sát, đều lao tới vì bảo thuật vô thượng, còn các cường giả và Tôn Giả cũng lần lượt hiện thân. Trên tế đàn, Thạch Hạo và Mạc Thương giao chiến dữ dội bằng phù văn, quyền cước và đại kích màu vàng; Mạc Thương dùng binh khí đâm vào ngực đối thủ nhưng bị Thạch Hạo né tránh rồi đánh bật đại kích lên trời. Khi có người định cướp đại kích, Mạc Thương vẫn khống chế được nó, khiến binh khí phóng phù văn và tia chớp vàng giết chết một cao thủ, làm những kẻ khác kinh sợ. Mạc Thương tiếp tục thi triển Hải Thần Nhất Trảm, triệu hồi đại kích, mọc đôi cánh Hải Thần vàng và dùng trạng thái thiên nhân hợp nhất để mượn lực trời đất, trong khi Thạch Hạo dùng mười tòa Động Thiên hóa thần hoàn phong tỏa hư không chống đỡ. Người quan chiến nhận ra Mạc Thương đã Hóa Linh Cảnh viên mãn, còn Thạch Hạo chưa viên mãn nên tưởng cậu sẽ bị đại kích xuyên chết. Nhưng mười Động Thiên của Thạch Hạo tương liên tẩm bổ thành dạng huyết nhục Động Thiên, giữ lại chiến kích mà không làm thân thể bị thương. Thạch Hạo lập tức tung một quyền mạnh mẽ đánh thủng lồng ngực Mạc Thương, làm áo giáp vàng nổ tung và khiến tất cả chấn kinh."},{"chuong":254,"tieuDe":"Thần Tàng Côn Bằng Mở Ra","tomTat":"Thạch Hạo một quyền đấm thủng ngực Mạc Thương, khiến hậu nhân Hải Thần trọng thương và phá vỡ trạng thái thiên nhân hợp nhất của hắn. Mạc Thương dùng dược tán luyện theo đan phương Hải Thần để chữa lành vết thương, khôi phục chiến lực rồi tiếp tục quyết chiến, trong khi Thạch Hạo còn cố ý xem xét khối thịt rơi ra như muốn ăn khiến đám đông kinh ngạc. Giữa lúc hai bên đại chiến, Côn Bằng Sào nổ tung mở ra hoàn toàn, lộ đạo tràng sáng chói, thần âm thái cổ và con đường dẫn vào thần tàng. Đám đông ùa vào tranh đoạt ao thần dịch, Mạc Thương dùng tế đàn sát phạt mở đường, còn Thạch Hạo thu được hơn mười giọt linh hải cuối. Tiến sâu hơn, mọi người phát hiện kim hải trong động phủ, đáy biển có động Côn Bằng chứa thần tàng nên Hàn Thiên, Mạc Thương, Hải tộc và cường giả lục địa cùng lao xuống. Dưới đáy biển, Thạch Hạo dùng mười tòa Động Thiên hợp thành thần hoàn, cầm cố hư không và xoắn nát những kẻ vây công, khiến nhiều Tôn Giả và vương hầu kiêng dè. Ở sâu trong động phủ, hai Tôn Giả tranh đoạt Thần Chiếu Thanh Đồng Đăng nhưng Hàn Thiên bất ngờ cướp đi, còn phù văn Côn Bằng cùng nhiều thái cổ pháp khí và chí bảo lộ ra phía trước, khiến tất cả điên cuồng xông vào."},{"chuong":255,"tieuDe":"Đoạt Bảo","tomTat":"Trong đạo tràng Côn Bằng dưới đáy biển, một cửa đá mở ra để lộ bình ngọc và chén ngọc chứa thần tửu, khiến hơn mười cường giả lao vào tranh đoạt. Mạc Thương cầm chiến kích màu vàng xuất hiện, chấn chết nhiều người rồi giao chiến với Thạch Hạo, nhưng Mao Cầu bất ngờ chui ra cướp bình ngọc, làm phá phong thần tửu trước khi Thạch Hạo thu bình vào Túi Càn Khôn. Ở nơi khác, dược lô Côn Bằng phun sương mù đen kịch độc giết hại nhiều người, Hàn Thiên dùng Thần Chiếu Đăng luyện hóa sạch độc vụ, còn Giao Tôn Giả nhận ra dấu vết Chân Giao bị luyện thành độc tán và lặng lẽ tiềm hành. Trong thạch thất sâu nhất, mọi người phát hiện bảo bình cắm hoa mới là chí bảo Ngọc Tịnh Bình giống vật của Tiểu Tây Thiên, khiến các vương hầu đại chiến tranh giành. Thạch Hạo không tranh bình mà nhắm đến bồ đoàn Côn Bằng, nhận ra nó là vật bện từ rễ cây non xanh biếc, nặng hơn mười vạn cân. Hắn xuất mười tòa Động Thiên chộp bồ đoàn rồi dùng chính bồ đoàn như búa đánh văng đại ấn của lão giả Hóa Linh cảnh, khiến thạch thất chấn động dữ dội."},{"chuong":256,"tieuDe":"Bảo Tàng","tomTat":"Trong động phủ Côn Bằng, bồ đoàn côn mộc và Ngọc Tịnh Bình khiến đám cường giả tranh đoạt dữ dội. Thạch Hạo thúc dục mười tòa Động Thiên hóa thần hoàn, dùng thanh kiếm gãy màu đen chém sạch một đám người rồi thu bồ đoàn vào Túi Càn Khôn, trong khi Ngọc Tịnh Bình bị kẻ khác lấy mất. Tiến sâu vào động phủ, mọi người phát hiện Luyện Binh Địa, nơi có hàn đàm chứa các khí phôi Thái Cổ như kiếm thai Long Cốt Thiết và bảo tháp Hỗn Độn Thổ, nhưng hàn khí thần tính có thể đóng băng người tới gần. Mạc Thương, Hàn Thiên, các Tôn Giả và sinh linh Thái Cổ Thần Sơn cùng lao vào tranh đoạt; Thạch Hạo dùng Đả Thần Thạch, nhờ chú ngữ ma nữ từng dạy, đánh trọng thương nhiều đối thủ. Sau cùng, Thạch Hạo bắt được Linh Lung Tháp Hỗn Độn Thổ, nhưng Cốt Tháp ẩn trên tóc lần đầu lên tiếng, nuốt hơn phân nửa Hỗn Độn Thổ để đổi cho hắn một lần cơ hội cứu mạng. Đả Thần Thạch được phần mảnh vụn còn lại để lột xác. Cuối chương, trời đất chấn động, đại điện phía trước động phủ mở ra và một con Côn Bằng bễ nghễ thế gian xuất hiện trong hỗn độn khí."},{"chuong":257,"tieuDe":"Thiên Hoang","tomTat":"Một tòa điện phủ cổ xưa khổng lồ trong thần sào Côn Bằng mở ra, cửa đá cao mấy vạn trượng hé lộ cảnh tượng như một thế giới riêng. Bên trong hiện ra bóng Côn Bằng sống động, khi hóa đại bàng vàng bay trong trời sao, khi hóa cá lớn màu đen rộng mấy vạn dặm, thần uy ép nhiều sinh linh quỳ xuống. Sau khi dị tượng biến mất, mọi người tiến vào đại điện và phát hiện một tế đàn cổ cao như núi, nơi có linh dược, thác tinh khí và cây Tinh Thần Thảo bảy lá sắp thành thánh dược. Trên tế đàn còn có nhiều binh khí thái cổ, nổi bật nhất là Thiên Hoang, đại kích chí cao Thiên Giai từng theo Côn Bằng chinh chiến, nay đã gãy ba đoạn nhưng vẫn phóng tinh hà đánh bay kẻ tới gần. Không ai, kể cả Tôn Giả, có thể câu thông hay thu lấy các thần binh, nên có người đề nghị phải dâng tàn cốt, lân phiến hoặc lông vũ Côn Bằng để leo lên tế đàn. Thạch Hạo cũng lấy ra một mảnh tàn cốt từng cùng ma nữ cướp từ Mạc Thương, khiến Mạc Thương giận dữ, rồi mọi người nhờ các di cốt mà lên được nơi cao nhất. Cuối chương, ánh mắt tất cả dồn vào bệ đá như quan tài, nơi đặt khối cốt màu vàng xen vân đen, phù văn chằng chịt lưu chuyển áo nghĩa chư thiên."},{"chuong":258,"tieuDe":"Phù Cốt Côn Bằng","tomTat":"Nguyên thủy phù cốt Côn Bằng lộ diện trên bệ đá, tỏa phù văn như ngân hà và hiện pháp tướng Côn Bằng che kín thiên địa, khiến quần hùng kinh hãi. Mọi người phát hiện khối cốt có vết nứt nhưng phù văn bên trong không thiếu, vẫn có thể tham ngộ, nên lòng tham càng bùng lên. Đại hỗn chiến nổ ra, các giáo chủ, Tôn Giả và sinh linh mạnh cùng lao vào tranh đoạt; Thạch Hạo chộp phù cốt lần đầu nhưng bị bảo cốt kháng cự đẩy ra. Mạc Thương dùng đại kích chém chết tông lão Nhân Ngư Tộc, đánh bại thiếu nữ thiên tài của tộc này; Hàn Thiên cầm Thần Chiếu Đăng phóng liệt diễm khiến các giáo chủ tránh lui. Thạch Hạo nổi giận tiến vào trạng thái cuồng bạo, mở mười Động Thiên, dùng đoạn kiếm, bảo thuật Toan Nghê và cánh Côn Bằng độc chiến quần hùng, khiến nhiều Tôn Giả cùng lão tổ hình thành ý định liên thủ diệt nó trước. Cuối chương, Thạch Hạo vận dụng Thân thể thành linh kết hợp Kim Tuyền Ba Văn Công để tiếp nạp phù văn, tinh khí, rồi mượn lực hỗn chiến nhảy về trung tâm bệ đá chộp lấy phù cốt."},{"chuong":259,"tieuDe":"Huyết Chiến Bát Phương","tomTat":"Thạch Hạo trọng thương vẫn tử chiến giữa vòng vây trong Côn Bằng Sào, dùng đoạn kiếm và bảo thuật giết vương hầu Hải tộc cùng nhiều cao thủ. Linh thân Thôn Thiên Tước hiện thân, muốn đoạt bảo thuật Côn Bằng và giết Thạch Hạo, nhưng bị thiếu niên liều mạng chém đứt tay, chặt thân, dẫm dưới chân rồi chặt đầu, khiến linh thân vẫn lạc. Bên ngoài vùng biển cấm, bản thể Thôn Thiên Tước cùng nhiều chí cường giả Hoang Vực tụ tập chờ kết quả tranh đoạt. Thạch Hạo kích phát khối nguyên thủy phù cốt Côn Bằng và phát hiện truyền thừa trong đó chỉ chưa đến một phần ba, không phải bảo thuật chân chính trọn vẹn. Khi Côn Bằng Hóa Ma động mở ra và phù cốt phân thành sáu khối, các cường giả điên cuồng tranh cướp. Thạch Hạo giả bộ sức kiệt, cố ý để Giao Tôn Giả và các lão tổ đánh mình rơi xuống Hóa Ma động, mượn cục diện hỗn loạn để tìm đường thoát thân."},{"chuong":260,"tieuDe":"Giải Thoát","tomTat":"Thạch Hạo trọng thương nhưng vẫn huyết chiến trong Côn Bằng Sào, dùng kiếm gãy và bảo thuật giết vương hầu Hải tộc rồi chống lại đợt tập sát của Mạc Thiên, Hàn Thiên cùng nhiều Tôn Giả. Linh thân Thôn Thiên Tước hiện thân tranh đoạt bảo thuật Côn Bằng, nhưng bị Thạch Hạo liều mạng chém đứt tay, chặt ngang thân, dẫm dưới chân và chặt đầu. Bản thể Thôn Thiên Tước ở cuối biển nổi giận, trong khi nhiều chí cường giả Hoang Vực tụ tập ngoài vùng biển cấm chờ kết quả. Thạch Hạo kích phát khối nguyên thủy phù cốt Côn Bằng và phát hiện truyền thừa trong đó chỉ ghi chưa đến một phần ba bảo thuật chân chính. Khối phù cốt mở ra Côn Bằng Hóa Ma động rồi phân thành sáu khối, khiến mọi người điên cuồng tranh cướp. Thạch Hạo giả bộ kiệt sức để Giao Tôn Giả và các lão tổ đánh mình rơi xuống động, thực chất mượn cục diện thiên băng địa liệt để tìm đường trốn thoát."},{"chuong":261,"tieuDe":"Bảo Thuật Chân Chính Đến Từ Hóa Ma Động","tomTat":"Sau khi lĩnh ngộ đầy đủ bảo thuật Côn Bằng tại thần sào, Thạch Hạo trở thành kẻ thù chung của các thế lực tranh đoạt bảo cốt; nó nhận ra sáu mảnh bảo cốt bên ngoài không phải truyền thừa hoàn chỉnh, còn bảo thuật chân chính nằm trong Hóa Ma động. Vì vậy Thạch Hạo cố ý mượn tay mọi người để rơi xuống vực sâu, tránh làm đích ngắm và đi tìm thần thông đầy đủ. Đi sâu xuống Hóa Ma động, nó thấy vô số bóng mờ và tiếng gào của hung thú Thái Cổ như Thanh Loan, Bệ Ngạn, Thôn Thiên Tước, rắn chín đầu, ma cầm và Toan Nghê từng bị Côn Bằng giết, hiểu rằng nơi đây là bãi tha ma và lò luyện hóa kẻ địch. Nhờ đã đi trên con đường Côn Bằng và vận chuyển phù văn đúng cách, Thạch Hạo vượt qua các cấm chế đủ nghiền nát Tôn Giả để tới cuối động. Sau hai cánh cửa đá, nó bước vào nhà đá thần thánh chứa ao máu Côn Bằng đỏ rực, nơi phù văn vàng đen hiển hóa thành Côn Bằng, côn ngư và chim bằng. Thạch Hạo chìm vào ngộ đạo sâu, quan sát biến hóa phù văn cùng cảnh tượng vũ trụ, rồi cuối cùng truyền thừa Côn Bằng tổ hợp thành lớp chiến y thần thánh hữu hình trên thân, khiến khí tức chí tôn tràn ngập chín tầng trời."},{"chuong":262,"tieuDe":"Kết Thúc Ở Cấm Kỵ Hải","tomTat":"Thạch Hạo chìm sâu trong truyền thừa Côn Bằng, thấy lại khí tượng Thái Cổ và lĩnh hội sự biến hóa từ chim Bằng thành cá Côn giữa vô số phù văn quy tắc. Trong lúc đó, bên ngoài Hóa Ma động, các thế lực trên tế đàn chém giết dữ dội để tranh sáu miếng bảo cốt Côn Bằng; Hỏa Viêm Ngư, Hàn Thiên, Thái Cổ Thần Sơn và các phe lớn lần lượt đoạt được phần của mình, còn Mạc Thương trọng thương phải ném bảo cốt để thoát thân. Chiến sự lan ra Bắc Hải, chân thân các Tôn Giả hiện thân tranh đoạt, khiến vùng biển hóa thành bãi chiến trường đẫm máu và có tin nhiều cường giả tuyệt đỉnh ngã xuống. Hang ổ Côn Bằng sau đó nứt vỡ chìm xuống đáy biển, các thần khí như Thiên Hoang, Lượng Thiên Xích, quạt vàng và chủy thủ Long Nha cũng biến mất trong đại dương, trong khi cấm chế còn tồn tại khiến không ai dám tùy tiện truy tìm. Riêng Thạch Hạo trong ao máu phát hiện một giọt chân huyết Côn Bằng được lưu lại cho người thừa kế, nhờ đó phạt cốt tẩy tủy, thân thể bị thương nặng hoàn toàn phục hồi và càng thêm thoát thai hoán cốt. Sau khi khắc ghi trọn vẹn bảo thuật Côn Bằng, cô đọng đạo pháp thành một chữ “Phù”, Thạch Hạo dùng nó hoàn thành bước Động Thiên Dưỡng Linh trong Hóa Linh cảnh. Nhận thấy con đường tu luyện ở nơi này đã viên mãn, nó quyết định rời Cấm Kỵ Hải để trở về sau hơn hai năm xa cách."},{"chuong":263,"tieuDe":"Trở Về","tomTat":"Trong ao máu Côn Bằng, Thạch Hạo hấp thu chân huyết và phù văn còn sót lại, đồng thời để linh thân Côn Bằng trong Động Thiên dung hợp áo nghĩa truyền thừa. Bóng Lông cũng từ túi càn khôn chui ra, được máu Côn Bằng gột rửa rồi rơi vào ngủ say. Sau nhiều tháng bế quan, Thạch Hạo tế luyện đủ mười Động Thiên, hoàn thành dưỡng Linh và đạt viên mãn Hóa Linh Cảnh theo ranh giới truyền thuyết. Hắn rời Hóa Ma Động bằng linh thân Côn Bằng, rồi lần lượt vào động Cực Dương, Cực Huyền Băng và Mộ Vẫn Tinh để chứng thực bản thân không còn bị các cực địa làm tổn hại. Bên ngoài, phù cốt Côn Bằng xuất thế khiến Bắc Hải đại loạn, tôn giả chết trận, Thái Cổ Thần Sơn và thần đảo hải ngoại đều nguyên khí đại thương, nhưng dư âm tranh đoạt vẫn chưa thật sự kết thúc. Cuối chương, một ông lão Nhân Tộc cụt tay mang cung lớn thoát khỏi rừng sâu màu đen sau mười ba năm, nhắc tới thù cũ với Tỳ Hưu, nhớ Tử Lăng và Hạo nhi, đồng thời mang theo thần đan muốn trở về đoàn tụ."},{"chuong":264,"tieuDe":"Thập Ngũ Gia","tomTat":"Thạch Hạo (Hùng Hài Tử) đạp sóng lướt trên Bắc Hải, sau hơn hai năm tìm bảo thuật đã trở thành cao thủ Hóa Linh Cảnh, khiến sinh linh Hải tộc khiếp sợ gọi là “sát tinh”; nhắc lại chiến công đại khai sát giới ở hang ổ Côn Bằng, đánh bại hai kỳ tài Bắc Hải Mạc Thương và Hàn Thiên. Sau trận chiến, các thần đảo và ngư cung đều đóng chặt núi chữa thương, Hải Giao lo lão tổ bị độc Chân Giao thương tổn khó qua khỏi. Thạch Hạo bắt hải sản mang về cho người thân Thạch thôn, vẫn cho rằng gia gia đã chết. Trong khi đó, Thập Ngũ gia (Đại Ma Thần, gia gia của Thạch Hạo) thoát khốn sau nhiều năm, đón ánh mặt trời chuẩn bị đoàn tụ tôn nhi; ông từng mất một tay trong trận chiến, thề tính sổ Tỳ Hưu và đập nát ngọn thần sơn đã truy sát mình. Ông bay tới đầm lầy Đại Hoang thu hồi bình chân huyết Tỳ Ngưu tuy đã tản mất một phần linh tính, rồi dùng bàn tay lớn giam cầm luyện hóa con Long Lân Tước làm tọa kỵ. Long Lân Tước đưa ông tới Hoàng Đô Thạch Quốc; Thập Ngũ gia hạ xuống trước cổng thành đi vào “về nhà”, khiến một giáo úy khiếp sợ lầm bẩm rằng Đại Ma Thần đã trở về, Hoàng Đô sẽ đại loạn."},{"chuong":265,"tieuDe":"Đại Ma Thần","tomTat":"Thập Ngũ gia cưỡi Long Lân Tước tiến vào Hoàng Đô sau mười ba năm bị tưởng đã chết, khí thế như lò lửa gây hỗn loạn cửa thành; Tiểu Lục tử của Chiến Vương phủ nhận ra ông rồi kinh sợ đuổi theo không kịp. Đám đông chấn động khi biết ông chính là lão Thập Ngũ của Võ Vương phủ, từng được xưng Đại Ma Thần, thần tiễn cái thế. Các chiến tướng Võ Vương phủ và Vũ tộc dùng tế đàn nhỏ truyền tin báo về gia tộc, linh cảm đại nạn sắp tới và tìm cách chặn tin. Ông tự báo tên Thạch Trung Thiên về tới Võ Vương phủ, được Thất ca kích động đón, phủ lập tức đóng cửa không tiếp khách. Trong phủ, Thạch Lạp và Thạch Uyên áp chế Tứ ca bế quan để che giấu chuyện năm đó, giải thích vợ chồng Thạch Tử Lăng đã đi Tây Cương. Thập Ngũ gia cảm nhận Thạch Hạo bất phàm cùng cấp Thạch Nghị dù Chí Tôn cốt chưa hiển hiện, rồi nổi giận quát “Hạo nhi của ta đâu?!” với thần âm như sấm sét làm rung đại điện, vỡ ghế Thạch Lạp và khiến hắn ngã xuống đất run rẩy."},{"chuong":266,"tieuDe":"Nổi Giận","tomTat":"Thập Ngũ gia trở về Võ Vương phủ và nhận ra bất thường khi Thạch Lạp hoảng loạn còn Thạch Uyên dùng Âm Ba công đánh thức hắn để ngăn lộ chuyện; ông truy hỏi tung tích Thạch Hạo, phát hiện nhiều huynh đệ và trưởng bối quen thuộc vắng mặt. Các trưởng bối cố trì hoãn, nói vợ chồng Tử Lăng cùng Thạch Hạo đã đi Tây Cương chờ Võ Vương xuất quan làm viện binh. Khi họ chỉ trả lời mơ hồ rằng Thạch Tử Lăng và Thạch Hạo “hẳn là” còn sống, Thập Ngũ gia bùng nộ; cung điện vỡ nát và tam đại sát trận tổ truyền kích hoạt để vây giết ông. Ông dùng phù văn trong mắt hóa Kim Sí Đại Bằng cùng nhật nguyệt tinh thần phá tan sát trận, bước ra khỏi cung điện nổ tung. Thạch Lạp dùng Thế Tử phù thoát thân, Thạch Uyên cũng bỏ chạy, khiến Thập Ngũ gia ném chín cây cờ lớn phong bế toàn Võ Vương phủ. Cuối cùng ông dùng thần thức rà soát toàn phủ, phá cấm chế cứu các lão huynh đệ và trưởng lão bị giam dưới lòng đất, khiến họ xúc động khi biết ông còn sống."},{"chuong":267,"tieuDe":"Gia Pháp","tomTat":"Thập Ngũ gia (Đại Ma Thần) trở về Võ Vương phủ sau nhiều năm tưởng đã chết, được các huynh đệ cũ vây quanh mừng rỡ. Ông đã dùng chín cây cờ lớn phong ấn cả phủ, dò hỏi về Tử Lăng và Hạo nhi. Nghe kể chuyện cháu Thạch Hạo bị cột giường sắt móc Chí Tôn cốt máu tươi đầm đìa, ông nổi giận đến mức hàng loạt cung điện nổ tung. Ông trừng phạt Thạch Lạp — đánh rơi toàn bộ hàm răng, đạp nát nửa thân; nghe hết đầu đuôi việc Thạch Tử Lăng đại náo phủ rồi bị bức tha hương thì phát điên như dã thú bị thương. Một tiếng hét của ông làm nổ tung hơn nửa cao thủ phe Thạch Uyên. Cuối cùng ông thi hành gia pháp: dùng Kim Sí Đại Bàng trấn áp nhất mạch Thạch Nghị, phế tu vi ông cố Thạch Nghị, vỗ chết trưởng bối phản đối và tuyên bố Võ Vương đã hồ đồ, có thể phế bỏ."},{"chuong":268,"tieuDe":"Quả Quyết","tomTat":"Đại Ma Thần công khai ý định chỉnh đốn Võ Vương phủ, tuyên bố có thể phế Võ Vương và ví phủ như đại thụ xanh tốt bên ngoài nhưng ruỗng mục bên trong. Khi bị mắng tạo phản, ông đảo ngược tội danh, cho rằng chính phe vi phạm tổ huấn, huynh đệ chém giết mới là phản nghịch, rồi lần lượt chỉ tội và dùng thần lực màu vàng nghiền nhiều trưởng bối thành tro. Bốn vị lão tổ Võ Vương phủ hiện thân can ngăn, viện lý do đại cục và bảo toàn Thạch Nghị người mang Trùng Đồng cùng Chí Tôn cốt đã vào Thượng Cổ Thánh Viện. Đại Ma Thần phản bác bằng giả định tự tay đoạt Trùng Đồng và thu Chí Tôn cốt, khẳng định chí tôn chân chính không do một khối cốt hay đôi mắt quyết định. Ông áp chế bốn lão tổ đến chảy máu, tiếp tục giết kẻ vi phạm tộc quy. Cuối chương, một giọng nói uy nghiêm từ xa truyền đến — Võ Vương cuối cùng đã xuất hiện."},{"chuong":269,"tieuDe":"Võ Vương","tomTat":"Võ Vương xuất quan giáng lâm trong hào quang đáng sợ, khiến phe đang bị vấn tội xem như hi vọng cuối cùng. Ông thừa nhận chuyện năm xưa bất công với dòng dõi Thập Ngũ gia nhưng lấy thân phận chủ tộc xin khoan dung cho nhất mạch Nghị nhi vì Thạch Nghị là trời sinh Thần Nhân Trùng Đồng giả. Thập Ngũ gia dứt khoát từ chối, khẳng định nếu cháu nội ác độc thì cũng chém, rồi công khai thách thức vị trí của Võ Vương khiến cả Hoàng Đô chấn động. Hai bên khai chiến: Võ Vương ra chưởng phù văn ngập trời và hóa thuồng luồng xám, Thập Ngũ gia gọi đại bàng cánh vàng đối kháng. Vừa đấu, Đại Ma Thần vừa hành gia pháp, đập chết tám chín người phạm tội, tha chết nhưng phế tu vi nhóm còn lại để họ sống chứng kiến tương lai Nghị nhi. Dư ba trận chiến khiến Thạch Lạp thân thể nổ tung chết oan, còn Thạch Uyên được Đại Ma Thần kịp đánh bay ra ngoài giữ mạng."},{"chuong":270,"tieuDe":"Quyết Đấu Ở Hoàng Đô","tomTat":"Sau khi phế các nguyên lão, Võ Vương ra lệnh khiêng họ xuống, còn Đại Ma Thần không truy sát vì xem việc hôm nay như chữa bệnh nặng cho bộ tộc. Võ Vương chất vấn Lão Thập Ngũ có hối lỗi không, nhận về một chưởng phù văn mở màn quyết đấu. Võ Vương thi triển đại thần thông Thế giới trong lòng bàn tay biến bàn tay thành thế giới có nhật nguyệt tinh thần, rồi hóa thành lò lửa liên hệ lư đồng để luyện hóa Đại Ma Thần, nhưng Thập Ngũ gia dùng cung lớn phá lư đồng và thoát vây. Hai bên liên tục đổi thần thông: Bệ Ngạn hoàng kim gặp Hắc Thần Phong, Hỗn Độn Đại Khí công đánh tan hắc phong, mắt bạc gặp vuốt rồng, làm kinh động toàn Hoàng Đô. Cuối cùng khi Võ Vương dùng lư đồng hộ thân và đại tinh phù văn cường công, Đại Ma Thần đánh nổ đại tinh, cứng đối cứng ép Võ Vương phun máu lảo đảo lùi lại."},{"chuong":271,"tieuDe":"Thần Tiễn Vô Song","tomTat":"Võ Vương ho máu nhưng vẫn phản kích bằng huyết hồ thần thông, biến máu thành hồ máu đầy phù văn để luyện hóa Thập Ngũ gia, song bị ông hóa đỉnh thu lại luyện thành huyết đan và chế nhạo là bảo dược huyết nhục. Võ Vương nổi giận để lộ chân hình lư đồng Kim Ô với sáu Kim Ô lửa; Thập Ngũ gia lấy cung lớn đối kháng, hấp thu biển lửa từ miệng lư. Bị chế giễu mất một tay, Đại Ma Thần dùng ống tay áo bên tay cụt quấn dây cung, bắn liên tiếp diệt sạch sáu Kim Ô phù văn và làm móp lư đồng Thượng Cổ. Hai bên phóng linh thân quyết chiến, Đại Ma Thần bắn chết một linh thân của Võ Vương. Võ Vương giải phong ấn tự áp chế khiến thực lực tăng vọt, đánh trọng thương Thập Ngũ gia; ông đáp lại bằng cách phóng thích lực lượng thần-ma trắng đen, cuối cùng bắn mũi tên trắng đen phá phù văn hộ thể khiến Võ Vương gãy xương, ngã ngửa vào phủ đệ, kết thúc trận chiến."},{"chuong":272,"tieuDe":"Vũ Vương","tomTat":"Võ Vương bị Thập Ngũ gia bắn thủng thân thể, thương thế nặng mất năng lực tái chiến, khiến Hoàng Đô và các vương hầu, đại tộc chấn động. Trước khi ngất, Võ Vương thừa nhận thất bại và nhắc rằng sau lưng Thạch Nghị có một vị Chí Cường giả; Đại Ma Thần tuyên bố không hứng thú với vị trí Võ Vương. Thập Ngũ gia thu chín cây cờ lớn mở trận ngoài phủ thì trời đổ mưa bất thường — thủ đoạn của Vũ tộc. Vũ Vương xuất hiện giữa mưa phù văn, lấy cớ khách đến thăm nhưng bị coi là khiêu khích; Đại Ma Thần nhắc mối thù Vũ tộc truy sát Thạch Tử Lăng ở Tây Cương, đưa hai lựa chọn cứng rắn rồi bắn thẳng mũi tên trắng đen, khiến Vũ Vương phải dùng thần vật liên quan Thần Linh chặn nhưng vẫn bị đánh bay mấy trăm trượng. Cuối chương, một người đàn ông mạnh mẽ bước ra từ màn mưa nhận đã mời Vũ Vương tới — Thạch Uyên nhận ra đó là Tử Đằng, cháu ruột hắn và là cha ruột của Thạch Nghị."},{"chuong":273,"tieuDe":"Thạch Tử Đằng","tomTat":"Trong màn mưa, Thạch Tử Đằng — con cháu Thạch tộc thần bí, cha của Nghị nhi — trở về Võ Vương phủ sau nhiều năm tu hành bên ngoài, đi mà không giọt mưa nào dính người, đồn đã bái nhập Thái Cổ Thần Sơn nhận Thái Cổ hung thú làm sư phụ. Hắn thỉnh an gia gia Thạch Uyên đã bị phế, rồi đối thoại với Thập Ngũ gia (Đại Ma Thần). Đại Ma Thần vạch trần Chí Tôn cốt của Nghị nhi đến từ tôn nhi hắn, bị Thạch Tử Lăng giết móc lấy; Thạch Tử Đằng phản bác thê tử mình cũng bị Thạch Tử Lăng giết. Thừa nhận mình và Thạch Tử Lăng không địch nổi Đại Ma Thần, Thạch Tử Đằng đã mời Vũ Vương tới. Vũ Vương xuất hiện, tuyên bố nhận lời mời dòng chính nhất mạch Võ Vương phủ, thay Võ Vương diệt phản nghịch, tru diệt Thạch Trung Thiên. Đại Ma Thần bắn hắc long bạch long từ hai mắt, áp đảo tuyệt đối, đánh Vũ Vương ho máu gãy tay và ép hắn lấy ra thứ có quan hệ với Thần Linh, mở màn một trận đại chiến."},{"chuong":274,"tieuDe":"Thần Khí","tomTat":"Đại Ma Thần Thạch Trung Thiên giao chiến với Vũ Vương giữa Hoàng Đô, dùng Tay ma hóa thành bàn tay đen khổng lồ áp chế lôi điện và đánh Vũ Vương ho máu. Vũ Vương phun máu kích hoạt Đại trận mưa máu của Vũ tộc, gọi ra chín hồ lô đỏ phun ánh kiếm khiến dư âm lan ra ngoài Hoàng Đô. Thạch Trung Thiên chuyển từ Tay ma sang Tay thần, bàn tay trắng như ngọc đánh tan mảnh vỡ hồ lô và dập tắt cơn bão năng lượng. Vũ Vương tiếp tục thức tỉnh Vũ Thần pháp chỉ, di vật Thượng Cổ Thần Linh của Vũ tộc, khiến các tấm hoàng kim trấn áp chiến trường và làm Đại Ma Thần bị thương. Trước uy áp thần khí, Thạch Trung Thiên kéo cung lớn bắn mũi tên Thượng Cổ Thần Linh, phá vỡ nhiều tấm pháp chỉ khiến Vũ Vương kinh sợ. Cuối cùng ông bắn thêm một mũi tên làm pháp chỉ nổ tung, rồi bắn trúng Vũ Vương, khiến nửa thân dưới đối thủ nổ nát và ngã trước Vũ Vương Phủ."},{"chuong":275,"tieuDe":"Lực Ép Vũ Tộc","tomTat":"Vũ Vương bị Đại Ma Thần đánh chỉ còn nửa thân thể, phải hiến tế phần thân nát cho pháp chỉ Vũ Thần để thoát khỏi tên thần và trốn vào Vũ Vương phủ. Thập Ngũ gia đứng trước phủ tuyên án Vũ tộc, nhắc lại chuyện họ từng đem thần khí tới Võ Vương phủ gây áp lực và đòi thanh lý môn hộ. Ông dùng cung lớn liên tiếp bắn phá đại môn, sân, phù văn phòng hộ và kiến trúc Vũ Vương phủ, khiến khu ngoài phủ thành phế tích trước mắt toàn Hoàng Đô. Người Vũ tộc nhớ lại pháp chỉ chữ Phạt từng bị Hùng Hài Tử nuốt mất một góc phù văn trong Hư Thần giới, nên pháp chỉ hiện tại có thể đã suy yếu trước thần khí của Đại Ma Thần. Bị ép đến đường cùng, Vũ tộc rút vào thần miếu, tế bái tượng đá Vũ Thần và kích hoạt trận pháp thần lưu lại, nhưng thần miếu vẫn bị tên thần màu bạc bắn rạn nứt rồi sụp đổ. Nhiều người Vũ tộc và mấy chục cường giả, trưởng lão lao ra phản kích nhưng đều bị Đại Ma Thần bắn nổ dưới cung lớn. Sau cùng, tượng đá và tế đàn còn lại phát ánh sáng bất thường, tạo tràng vực niêm phong phủ đệ khiến Đại Ma Thần không tiến vào thần thổ Vũ tộc. Khi Hoàng Đô còn chấn động vì một người ép cả Vũ tộc không ngẩng đầu nổi, một bóng người cao lớn cầm bảo tháp xuất hiện trên đường chính."},{"chuong":276,"tieuDe":"Sinh Linh Thần Sơn","tomTat":"Thạch Tử Đằng quay lại Võ Vương phủ, dẫn theo một nam tử tóc xanh đến từ Thái Cổ Thần Sơn vào nơi sâu nhất trong phủ. Người tóc xanh chỉ bằng một ánh mắt đã khiến một nguyên lão hồn phách chấn động, rồi đối thoại với Thạch Trung Thiên và bị ông vạch trần chỉ là một linh thân đang trọng thương. Hắn thả tám khối cốt ra tám hướng, phong ấn toàn bộ Võ Vương phủ để khóa đường lui, sau đó triển khai đại chiến với Đại Ma Thần. Hai bên liên tục dùng Đóng băng cực hạn, Xích đen trật tự, thần thông mở cửa địa ngục, chân long song hình và cung tên để công sát. Người tóc xanh tế ra tháp đồng Pháp khí Thần Linh, hóa tháp lớn như núi và hút Thạch Trung Thiên vào trong, nhưng Đại Ma Thần vẫn giết thoát ra ngoài dù bị thương nặng. Khi hai người tiếp tục tử chiến, Nhân Hoàng lặng lẽ xuất hiện trong Võ Vương phủ, khiến mọi người cúi bái và tuyên bố trận chiến nên kết thúc."},{"chuong":277,"tieuDe":"Đại Chiến Ở Hoàng Đô Kết Thúc","tomTat":"Nhân Hoàng hiện thân tại Hoàng Đô, răn cường giả Ma Linh hồ không nên tới đây và khiến toàn trường chấn động trước uy thế của mình. Người tóc xanh nói bản thân chỉ là một tấm thân tàn, còn Thạch Trung Thiên vẫn cứng rắn không chịu nhận sai hay rời Võ Vương phủ, nên Nhân Hoàng cho phép hai bên quyết chiến sinh tử. Trận chiến lan rộng khiến các bá chủ kéo tới, nhưng khu vực phủ đệ đã bị tám khối cốt phong ấn, hư không cũng bị người tóc xanh tiếp tục niêm phong. Thạch Trung Thiên trong thế cụt tay và bị thương vẫn mở nhiều Động Thiên, phóng linh thân Kim Sí Đại Bằng, Toan Nghê, Bệ Ngạn và chim tước đỏ đậm vây công, buộc người tóc xanh lộ bản thể Bích Ma Hắc Đồng Chu. Ma Chu dùng tơ nhện lôi điện, sát trận phù cốt và thần thông giam cầm để ép Thạch Trung Thiên vào tử địa; giữa lúc đó A Man bí mật truyền âm nhắc ông tránh sát cơ. Khi thân thể bị khóa, Thạch Trung Thiên dùng tâm niệm từ mi tâm hóa thành bảo cung và thần tiễn, bắn thủng đầu Ma Chu rồi lao tới chém rơi đầu nó. Đại chiến ở Hoàng Đô vì thế kết thúc bằng chiến thắng của Thập Ngũ gia."},{"chuong":278,"tieuDe":"Trở Về Từ Hải Ngoại","tomTat":"Trận chiến ở Hoàng Đô kết thúc khi Thập Ngũ gia chém chết linh thân Bích Ma Hắc Đồng Chu, khiến tháp đồng chứa ý chí Ma Chu mở thông đạo rồi biến mất. Nhân Hoàng tuyên bố mọi việc chấm dứt, sau đó triệu Đại Ma Thần vào cung và truyền ra tin muốn phong ông thành Ma Thần Vương, làm các tộc lớn trong Hoàng Đô chấn động. Ở Bắc Hải, Thạch Hạo cùng Bóng Lông đi thuyền U Linh trở về đất liền sau hai năm lưu lạc hải ngoại, trên đường còn thu hải sản mang về cho Thạch thôn. Cậu lặn xuống đáy biển thăm dò nơi bị đồn là Long cung, phát hiện đó là thành trì Nhân Ngư xây bằng trân châu thủy tinh, đầy bảo vật quý như Huyết tinh châu và Hải Lam Tủy. Cô gái Nhân Ngư Tộc từng được Thạch Hạo cứu ở hang ổ Côn Bằng nhận ra cậu, tặng nhiều vật liệu quý rồi nhờ tộc nhân mở truyền tống trận đưa cậu về Tây Cương Thạch Quốc. Sau một tháng vượt núi rừng, Thạch Hạo trở lại Thạch thôn, thấy Liễu Thần đã lột xác mạnh mẽ với năm mươi cành xanh. Cậu bí mật báo Liễu Thần rằng mình đã lấy được bảo thuật Côn Bằng hoàn chỉnh, còn Liễu Thần khiến cậu kinh hãi khi báo tin tổ phụ của cậu đã xuất hiện."},{"chuong":279,"tieuDe":"Lại Trở Về Rồi","tomTat":"Liễu Thần báo cho Thạch Hạo biết tổ phụ của nó vẫn còn sống, đang ở Hoàng Đô Thạch Quốc, khiến Thạch Hạo chấn động buồn vui sợ đan xen khi hồi tưởng chuyện tổ phụ vì đi tìm thuần huyết mà đắc tội Tỳ Hưu nhất mạch rồi mất tích. Thạch Hạo trở về Thạch thôn sau hai năm, được cả thôn vui mừng xúm lại đón, mở tiệc hải sản lớn với các hải thú kỳ lạ khiến người Đại Hoang kinh ngạc. Thôn nay linh khí đầy khắp nhờ Cây đào bạc chuẩn thánh dược và mấy chục cây linh dược; Bát Trân Kê thành thành viên thôn được bảo vệ đặc biệt, Tiểu Bạch đã thành hung thú mạnh, Đại Hồng, Nhị Ngốc Tử, Tử Vân đều vào núi tìm Chí Tôn thần tàng. Nghe tin tổ phụ đại náo Vũ Vương phủ, một mũi tên bắn đứt thân thể Vũ Vương và bắn chết Thái Cổ Bích Ma Hắc Đồng Chu, Thạch Hạo xúc động rơi nước mắt. Đêm đó cả thôn quây quần bên lửa trại; Thạch Hạo đem bảo thuật Côn Bằng nói cho Liễu Thần khiến cả cây phát sáng và thu hoạch cảm ngộ lớn. Sáng ra Thạch Hạo một mình lên đường qua thông đạo Liễu Thần, giữa đường thấy cảnh chiến của một Thái Cổ Ma Chu to như núi với sinh linh phát sáng, cuối cùng ra khỏi thông đạo cách Hoàng Đô Thạch Quốc mấy trăm dặm và lao nhanh tới tòa thành nơi nó sinh ra."},{"chuong":280,"tieuDe":"Hồ Ly Tinh","tomTat":"Thạch Hạo che giấu chân dung thật khi tiến vào Hoàng Đô Thạch Quốc, vì thủ phủ đang bất ổn sau biến cố Thập Ngũ gia đại náo và bản thân hắn từng kết thù với nhiều thế lực hải ngoại. Hắn quan sát tòa thành cổ hùng vĩ, dòng người phồn hoa, các cửa hàng bảo cốt, lão dược, binh khí và hung thú bị giam bán, rồi dừng trước một nơi rao bán Hồ nữ. Tại đây, một khách qua đường giải thích Hồ nữ chỉ còn chút huyết thống Hồ Tộc, còn Hồ Ly Tinh chân chính là hung thú mạnh mẽ hóa hình; Thạch Hạo bị bà chủ trêu chọc nên quay lại véo mặt búng trán bà rồi rời đi. Trong điện phủ phía sau, Hồ Ly Tinh áo trắng cầm thần bích thấy vật này phát sáng khi Thạch Hạo xuất hiện, nhận định hắn có tiềm năng trở thành bá chủ Hoang Vực và sai người chú ý. Nàng cùng bà chủ nhắc tới thế lực đáng sợ phía sau, việc chuẩn bị cho đại loạn Hoang Vực và kế hoạch đi sứ Nhân Hoàng Thạch Quốc. Sau đó, tiểu tháp truyền âm cho Thạch Hạo biết trong khu kiến trúc có một khối ngọc bích thần liên quan tới điều kiện bốn khối để đổi lấy một cơ hội sử dụng nó, khiến Thạch Hạo hiểu mình vừa bị cảm ứng. Hắn lập tức vận dụng cổ pháp trong Nguyên Thủy Chân Giải để thu liễm khí cơ, rồi tiếp tục nghe tin đại thọ Nhân Hoàng sắp khiến Hoàng Đô phong vân hội tụ, Thái Cổ Thần Sơn và thiên tài các Cổ Quốc có thể kéo tới, thậm chí Thạch Nghị có lẽ sắp trở về từ vết nứt không gian tại di chỉ Bổ Thiên Các."},{"chuong":281,"tieuDe":"Quyết Định Cường Thế","tomTat":"Thạch Hạo đã tới Hoàng Đô Thạch Quốc hai ngày nhưng chưa vào Võ Vương phủ, vì nhiều tin đồn cho thấy tổ phụ Đại Ma Thần có thể đã rời đi — bị Tôn Giả Ma Linh hồ và Thái Cổ Ma Chu nhắm tới, hoặc rời thành đi tìm Thạch Tử Lăng. Nó liên hệ tin Thái Cổ Ma Chu xuất động với cảnh từng thấy trong thông đạo hư không: một con nhện khổng lồ giao chiến với một người trên núi cao. Thạch Tử Đằng trở lại Hoàng Đô cùng vài cường giả, rồi một linh thân khác của Thái Cổ Ma Chu — nam nhân tóc xanh biếc — tiến vào thành với cớ chúc thọ Nhân Hoàng. Thạch Tử Đằng được Nhân Hoàng triệu vào cung mật đàm; lời hắn truyền ra đề cao Thạch Nghị là thiếu niên chí tôn có Bổ Thiên thuật và xin thần huyết Tế Linh để tẩy thân, khiến các vương hầu suy đoán về vấn đề kế thừa. Phẫn nộ trước những lời khinh miệt chi mạch mình, Thạch Hạo quyết định cho thiên hạ biết mình còn sống và phơi bày chuyện Chí Tôn cốt năm xưa. Nó chuẩn bị tiểu tháp làm át chủ bài nhưng chỉ đủ dùng một lần, nên tìm kỳ trân trong Hoàng Đô; theo cảm ứng của tiểu tháp, nó tới nhà đấu giá Cốt Cổ và lần đầu nhìn thấy Thạch Tử Đằng trực diện."},{"chuong":282,"tieuDe":"Phòng Đấu Giá Cốt Cổ","tomTat":"Một chiến xa hoàng kim do tám hung thú kéo lao tới phòng đấu giá Cốt Cổ ở Hoàng Đô, được nhận ra là của Hỗn Thiên hầu — vương hầu trẻ họ Thạch trấn thủ biên cương lập công đánh Mộc tộc, tới vì thanh Huyết Ma Thước. Thạch Hạo đứng ngoài cửa nghe nghị luận thu thập tin tức, thấy Thập lục công chúa được Nhân Hoàng yêu thích và nhiều nhóm quyền quý lần lượt vào. Khi vào trong, nó thấy đại sảnh hoa lệ trưng bày bộ hài cốt Nhai Tí khổng lồ với nguyên thủy phù cốt cung cấp thần lực cho cả tòa nhà. Định vào phòng khách quý, Thạch Hạo bị người giúp việc khinh thường vì mặc áo da thú và bị hậu nhân Tây Minh hầu tranh phòng, liền lấy một khối Hải Lam tủy lớn nện ngã người giúp việc, khiến cả phòng đấu giá kinh động. Chuyên gia giám định nhận ra kỳ thạch quý, các lão giả quở trách người giúp việc rồi xin lỗi và hỏi có muốn đưa Hải Lam tủy vào đấu giá. Vật đấu giá đầu tiên là khối cốt trắng sáng cực giống Nguyên Thủy Chân Giải, được gọi là Thiên cốt cứng rắn không thể phá hủy, khiến Thạch Hạo quyết tâm mua bằng được nhờ nền tài lực thu được ở hải ngoại."},{"chuong":283,"tieuDe":"Thu Hoạch Cực Lớn","tomTat":"Một khối tàn cốt Thiên Cốt trắng muốt được đưa lên đấu giá, tuy không trọn vẹn, không có phù văn hay công dụng rõ ràng nhưng lại cực kỳ cứng rắn, khiến Thạch Hạo nghi ngờ nó cùng tính chất với Nguyên Thủy Chân Giải. Không có tinh bích, Thạch Hạo lấy Hải Lam Tủy trong Túi Càn Khôn ra làm giá, cạnh tranh với Đại tiểu thư Lôi tộc, người lần lượt đưa phù cốt màu tím và Long Cốt Thiết để tranh đoạt. Khi khối Hải Lam Tủy lớn được đưa lên, đối phương bỏ cuộc, đồng thời thân phận minh châu Lôi tộc và tin đồn về muội muội có thể đối đầu Thạch Nghị được hé lộ. Thạch Hạo đoạt được tàn cốt, rồi Tiểu tháp truyền âm cho biết bên trong ẩn giấu một đại pháp vô thượng, khiến nó càng quyết tâm giữ lại. Sau đó Huyết Ma Xích xuất hiện và bị Hỗn Thiên Hầu lấy đi, không ai dám tranh, còn Tiểu tháp lại ám chỉ loại binh khí này có thể cứu mạng. Cuối cùng, Thạch Hạo dùng phương thuốc tổ truyền Thạch Thôn đổi lấy mai rùa khắc Bảo thuật Huyền Quy, thử tu liền khiến thân thể phát hào quang vàng đất và trở nên cứng rắn, thu hoạch trong buổi đấu giá tăng mạnh."},{"chuong":284,"tieuDe":"Kỳ Trân Dị Bảo","tomTat":"Trên hội đấu giá Cốt Cổ tại Hoàng Đô, ông lão tóc bạc và cô gái áo đỏ dẫn dắt đưa ra viên Tị Hỏa Châu đỏ thẫm kháng hỏa, cuối cùng Thập Lục công chúa — con gái Nhân Hoàng yêu quý nhất — dùng nguyên thủy phù cốt đoạt được. Nhiều trân bảo lần lượt bày ra: Thiên Ma Tán về tay một Vương gia, còn Thạch Hạo hỏi tiểu tháp thì nó trầm mặc không đáp. Khi Súc Địa phù xuất hiện, Thạch Hạo phân phó chặt một khối lớn Hải Lam Tủy đem đấu giá khiến không ai dám tranh, đoạt được bảo phù dùng để đào tẩu. Da Hư Không Thú cực hiếm rồi rơi vào tay một người thần bí trốn trong gian khách quý dù Thạch Hạo đỏ mắt tranh. Sau cùng, một tiểu nhân màu đen nhỏ như nắm đấm, phù văn nứt nẻ bị mọi người coi là phế bảo được đưa ra, nhưng tiểu tháp bất ngờ truyền âm giục Thạch Hạo cạnh tranh, khẳng định đủ hưởng thụ cả đời và tiếc không nỡ tiêu hóa. Thạch Hạo kinh hãi nhận ra đây là chí bảo nhân gian, càng suy đoán lai lịch phi phàm của tiểu tháp."},{"chuong":285,"tieuDe":"Bất Diệt Kim Thân","tomTat":"Tại Phòng đấu giá Cốt Cổ, Tiểu tháp nhận ra món chiến ngẫu tàn phá đang được bán thực chất là Bất Diệt Kim Thân, một bảo cụ hình người từ thời Thái Cổ từng bị tu bổ sai rồi hư hại sau đại chiến. Nó cho Thạch Hạo biết nếu loại bỏ phần tu bổ thời Thượng Cổ, cổ bảo này có thể khôi phục tới chiến lực cấp vương hầu, thậm chí còn có tiềm lực cao hơn nếu tế luyện về hình dạng Thái Cổ. Thạch Hạo âm thầm theo giá từng chút và mua được bảo vật với chi phí nhỏ vì đa số người trong đấu giá hội không nhận ra giá trị thật. Ngay sau khi búa đã gõ, Thập Cửu hoàng tử cùng một nữ tử áo trắng che mặt tới nơi, muốn chen vào tranh món vừa bán; Thiên Hồ tiên tử trong phòng khách quý cũng nhận ra bất thường và muốn mua lại. Thạch Hạo từ chối cả lời đề nghị giá cao của Thập Cửu hoàng tử lẫn lời mời của Thiên Hồ tiên tử, lấy cớ yêu thích nghiên cứu chiến ngẫu để giữ lại chí bảo. Sau đó hắn tiếp tục mua một khối tài liệu cổ mà Tiểu tháp đánh giá có thể giúp nó thêm nửa lần xuất thủ. Cuối đấu giá hội, một hạt châu nứt dính vết máu đen bị hai nữ tử bỏ qua vì tưởng đã hỏng, nhưng Tiểu tháp nhận ra đó là con mắt có nguồn gốc từ Trùng Đồng giả. Thạch Hạo vì hai chữ Trùng Đồng mà chấn động trong lòng và quyết định toàn lực tranh đoạt món cuối cùng này."},{"chuong":286,"tieuDe":"Thần Vật Khó Nắm","tomTat":"Sau khi đấu giá kết thúc, Thạch Hạo cầm thạch châu và chỉ muốn rời đi để kiểm kê thu hoạch. Thập Cửu hoàng tử ngỏ ý mua lại người tí hon màu đen nhưng bị từ chối, còn Tiên tử che mặt mời Thạch Hạo tham gia một buổi tụ hội của tinh anh các tộc. Thiên Hồ tiên tử xuất hiện, trêu ghẹo và giao thủ bằng phù văn với Tiên tử che mặt, khiến lụa che mặt bị lật ra nửa gương mặt tuyệt mỹ; các vương hầu sau đó bàn tán về lai lịch vực ngoại của Tiên tử che mặt và thế lực đáng sợ sau Thiên Hồ tiên tử. Trở về khách sạn, Thạch Hạo kiểm tra khối xương trắng, Súc Địa phù và các vật đoạt được, biết khối xương cần ghép thêm mới lộ thiên cơ, còn Súc Địa phù vẫn hoàn chỉnh. Hắn bóc lớp ngoài của người tí hon màu đen, nhờ tiểu tháp lộ ra Bất Diệt Kim Thân tàn tạ; khi dung hợp vào huyết nhục, nó hóa thành chiến giáp hắc kim khiến chiến lực hắn tạm thời vượt Hóa Linh cảnh, nhưng tiểu tháp nhắc phải dừng vì thần vật chưa hoàn chỉnh. Cuối cùng, Thạch Hạo phá thạch châu bọc máu Thần Ma, phát hiện mũi tên đồng đen mục nát và Trùng Đồng Thượng Cổ bên trong; khi tế luyện, Trùng Đồng phát sáng, chứng tỏ vẫn còn sinh cơ và giá trị khó lường."},{"chuong":287,"tieuDe":"Trùng Đồng","tomTat":"Thạch Hạo thử thúc dục nhãn cầu Trùng Đồng giả lấy được từ thạch châu và phát hiện nó vẫn còn dấu ấn sinh mệnh, có thể nhìn xuyên cảnh vật, nhìn thấu bản chất, phát chùm sáng phá diệt bảo cụ và khiến chuyển động của đối thủ trở nên chậm trong cảm ứng. Hắn dùng ánh sáng từ con mắt đánh nát mũi tên đồng thành bụi, từ đó nhận ra Trùng Đồng giả dù không đoạt chí tôn cốt vẫn cực kỳ đáng sợ. Sau khi loại bỏ ý định dùng thân mình tẩm bổ hoặc đặt nhãn cầu vào mi tâm bản thể, Thạch Hạo diễn hóa một linh thân hình người trong Động Thiên rồi đặt con mắt vào mi tâm linh thân để nuôi dưỡng và lĩnh ngộ phù văn nguyên thủy bên trong. Kiểm kê bảo vật đấu giá, hắn được Tiểu tháp chỉ ra khối bùn hôi là thịt nát của Thiên Thần, vật có thể đổi lấy nửa lần xuất thủ của tháp, đồng thời nghe Tiểu tháp nói về trao đổi đồng giá và sự cân đối của thế gian. Thạch Hạo tiếp tục nghiên cứu khối mai rùa Huyền Quy, dùng bồ đoàn Côn Bằng trợ ngộ đạo nhiều ngày và nắm giữ đại bộ phận bảo thuật Huyền Quy. Cuối chương, một tiểu nha đầu hồ ly xinh đẹp tìm đến truyền lời mời của tiểu thư nhà mình, còn nói muốn tìm chồng cho một vị tiên tử thánh khiết, khiến Thạch Hạo đùa hỏi có thể mua một tặng một hay không."},{"chuong":288,"tieuDe":"Có Bệnh Thì Phải Trị","tomTat":"Hoàng Đô Thạch Quốc náo nhiệt vì các vương hầu, thiên tài quý tộc, hoàng tử công chúa từ xa trở về chúc thọ Nhân Hoàng, khiến đường phố đầy chiến xa và hung thú kéo xe. Thạch Hạo đi bộ tới Thanh Lâm viên nên trở nên khác người giữa đám con cháu quyền quý, đồng thời chứng kiến va chạm giữa các chiến xa và hiểu thêm phong tục lấy võ lập quốc của Thạch Quốc. Trên đường, Thiên Hồ tiên tử cùng Tiểu Hồ Ly dừng xe kéo trong suốt mời hắn đi nhờ, nhưng Thạch Hạo nhận ra nữ tử Thiên Hồ tộc rất nguy hiểm nên từ chối. Sau đó một chiến xa tám hung thú lao tới ép hắn, phu xe hạch hỏi chuyện Thiên Hồ tiên tử rồi dùng roi đồng phù văn tấn công. Thạch Hạo đá gãy roi, đánh phu xe văng xa, tiếp tục dùng bóng huyền quy và tia chớp tím trấn áp thiếu niên chủ nhân chiến xa cùng đồng bọn. Cuối cùng hắn tuyên bố chiếm chiếc chiến xa và nghênh ngang rời đi, để lại nhóm quý tộc bị hạ nhục ngay trên đường tới Thanh Lâm viên."},{"chuong":289,"tieuDe":"Anh Kiệt Tụ Hội","tomTat":"Sau khi bị Thạch Hạo đánh bại và cướp chiến xa thanh đồng, nhóm thiếu niên phía sau vừa tức giận vừa lo sợ vì cỗ xe là của Lăng Vân hầu. Thạch Hạo lái chiến xa rời đi, dùng bảo thuật Kim Sí Bằng Điểu không đầy đủ để áp chế tám hung thú kéo xe, cố ý không thi triển Bảo thuật Côn Bằng hoàn chỉnh vì sợ lộ bí mật. Nó tiến vào Thanh Lâm viên, nơi có nhiều chiến xa vương hầu và tuấn kiệt trẻ tuổi tụ họp quanh hồ lớn. Tại đây, Thập Lục công chúa, chàng trai tóc tím, Hỗn Thiên hầu cùng muội muội hắn lần lượt xuất hiện, cho thấy hội này quy tụ lớp trẻ quyền quý và cao thủ của Hoàng Đô. Lý Bạch Đinh gây náo động khi bị vị hôn thê Lôi tộc tuyên bố từ hôn, rồi thi triển Kim Cương Bất Hoại của Tiểu Tây Thiên đánh bay lão bộc. Thiên Hồ tiên tử lại đến trêu chọc Thạch Hạo về chuyện bán một vị tiên tử thánh khiết. Cuối chương, người của Võ Vương phủ bàn đến Đại Ma Thần, Thạch Nghị và nội bộ chia rẽ, rồi một người thuộc nhất mạch Đại Ma Thần say rượu công bố rằng trong phủ còn một trời sinh Chí Tôn khác tên là Thạch Hạo, khiến toàn bộ khu hồ chấn động."},{"chuong":290,"tieuDe":"Tiên Tử Đến Từ Vực Ngoại","tomTat":"Hoàng Đô bàn tán về danh xưng trời sinh Chí Tôn và nhắc lại những nhân vật nổi bật của Võ Vương phủ như Đại Ma Thần, Thạch Tử Lăng, Thạch Tử Đằng và Thạch Nghị. Bên hồ nước xanh lam, một tiên tử áo trắng che mặt thổi sáo ngọc, khiến cá chép rồng, linh ngư và dị cầm tụ về, càng làm con cháu vương hầu cảm thấy nàng cao xa khó với tới. Thiếu niên tóc tím Chân Chấn xuất hiện, tự nhận không thuộc Hoàng Vực, gây hấn với đám người và cảnh báo khu vực này sẽ đại loạn. Hỗn Thiên hầu dùng Thần Ma Huyết Xích đối đầu hắn, nhưng tiên tử che mặt ngăn cả hai rồi dùng thần âm hóa núi vàng trấn áp Chân Chấn phun máu. Thiên Hồ tiên tử hiện thân, cùng tiên tử che mặt nhắc đến cuộc cá cược nhiều năm, trận chiến mạnh nhất và cuộc khai chiến sắp tới giữa hai giáo phái. Cuối chương, Thạch Hạo đang ăn uống bỗng bị triệu vào một không gian đặc biệt trước mặt hai tiên tử, vẫn cầm thịt khô uống rượu và buông lời trêu chọc họ."},{"chuong":291,"tieuDe":"Ma Nữ Lại Xuất Hiện","tomTat":"Trong Thần Ma Chiến Vực, Thiên Hồ tiên tử kéo Thạch Hạo vào cuộc tranh đấu lâu năm với Nguyệt Thiền, tuyên bố nó là chiến giả nàng lựa chọn tại Hoang Vực. Qua những lời nhắc về Bắc Hải, tổ Côn Bằng và lần uống thần tửu dưới trăng, Thạch Hạo nhận ra nàng chính là ma nữ từng nhiều lần hợp tác với mình. Ma nữ dùng chiến vực áp chế tu vi của mọi người xuống Động Thiên cảnh rồi kích động Thạch Hạo giao đấu với Nguyệt Thiền. Khi Thạch Hạo hiển hóa mười Động Thiên, Nguyệt Thiền cũng bộc lộ thành tựu tương đương, đồng thời triệu hiện các thần ảnh trong động thiên để hợp lực trấn áp đối thủ. Dù tự tin vào sức mạnh cùng cảnh giới, Thạch Hạo chuyển sang phòng ngự vì chưa rõ đúng sai trong ân oán giữa hai nàng và không muốn bị cuốn vào một trận tử chiến. Trong lúc hai bên giằng co, ma nữ tiết lộ Nguyệt Thiền đến Hoàng Đô để lôi kéo Thạch Nghị, người được nàng xem là bá chủ tương lai của Hoang Vực, khiến ánh mắt Thạch Hạo thoáng hiện vẻ sắc lạnh."},{"chuong":292,"tieuDe":"Chiến Tiên Tử","tomTat":"Thạch Hạo nhớ lại mục đích đến Hoàng Đô để gặp tổ phụ và giải quyết ân oán với mẹ con Thạch Nghị, vì thế xem Nguyệt Thiền, người chủ động tìm đến Trùng Đồng giả, là đối thủ tiềm tàng. Dưới sự kích động của Thiên Hồ tiên tử, nó vận dụng Huyền Quy cùng biển xanh trấn áp, liên tiếp phá tan phù văn phòng ngự và chú thuật nguyền rủa của Nguyệt Thiền. Nguyệt Thiền triển khai mười Động Thiên, tạo ra thế công như Quan Âm ngàn tay, nhưng Thạch Hạo linh hoạt đánh tan từng chưởng ấn rồi áp sát, khiến cuộc va chạm kết thúc bất phân thắng bại. Nàng giải thích rằng mình chỉ muốn kiểm chứng thực lực của Thạch Nghị, song Thiên Hồ tiên tử cho rằng nàng định mời chào hắn trở thành bá chủ. Khi Thạch Hạo dùng thập đại Động Thiên tiếp tục tấn công, Nguyệt Thiền thi triển thần thông Hóa Thiên để hóa giải và chuyển hướng sức mạnh, khiến một ngọn núi ở xa bị nghiền thành bột. Dù có đại thần thông hộ thân, nàng vẫn chịu áp lực nặng nề trước chiến lực gần như vô địch cùng cảnh giới của Thạch Hạo. Cuối cùng, Thiên Hồ tiên tử trực tiếp nhập cuộc, cùng Thạch Hạo hình thành thế vây khiến Nguyệt Thiền đứng trước nguy cơ bị bắt sống."},{"chuong":293,"tieuDe":"Tập Hợp Các Lá Bài Tẩy","tomTat":"Thạch Hạo phối hợp cùng Thiên Hồ tiên tử vây ép Nguyệt Thiền trong Thần Ma Chiến Vực, nhưng cuối cùng phát hiện đối thủ chỉ là một linh thân gần như chân ngã, được chân thân bên ngoài phá không gian thu hồi. Ngay sau đó, thuộc hạ của một tiểu chủ nhân Thái Cổ Thần Sơn dùng lưới cấp vương hầu định bắt hai tiên tử, song bị họ hợp lực phá bảo cụ rồi tiêu diệt cả người lẫn chim cưỡi. Không ai nhận ra vai trò thật sự của Thạch Hạo trong trận chiến, nên cậu bình thản trở lại yến tiệc, tiện tay đánh Liễu Hàn cùng những kẻ được thuê trả thù xuống hồ và từ chối bán khối xương nghi liên quan đến Nguyên Thủy Chân Giải. Khi khu đấu bảo mở cửa, tiểu tháp cảm ứng được một cây chủy thủ hư hỏng trong đống cổ khí từ vùng phế tích, khiến Thạch Hạo lập tức mua lại với giá rẻ. Tiểu tháp nuốt cây chủy thủ, tiết lộ nó được hóa thành từ răng rồng con và đổi lại cam kết cứu Thạch Hạo thêm một lần. Có thêm lá bài tẩy bảo mệnh, Thạch Hạo không còn e ngại việc đối đầu Thạch Tử Đằng, kẻ đứng sau hắn hay Thái Cổ Ma Chu, đồng thời chuẩn bị công khai rằng mình vẫn còn sống để tin tức sớm truyền tới gia gia."},{"chuong":294,"tieuDe":"Phong Ba","tomTat":"Có tiểu tháp làm át chủ bài, Thạch Hạo vẫn kiềm chế ý định truy tìm Thái Cổ Ma Chu ngay lập tức, quyết định chờ đại thọ Nhân Hoàng hoặc trở lại Võ Vương phủ để tránh đánh động kẻ địch. Tại khu bán bảo vật, nó dùng nhãn cầu của trời sinh thần nhân giám định một chiếc Chén Hóa Thiên hàng nhái đã vỡ và phát hiện vật liệu thần tính ẩn bên trong. Thạch Hạo thắng Cổ Linh Ngọc trong cuộc tranh giá bằng sáu viên Huyết Tinh Châu, sau đó tế luyện chiếc chén và nhanh chóng nắm được cách sử dụng. Cổ Linh Ngọc dẫn Cổ Linh Lung cùng nhiều con cháu quyền quý đến gây sức ép, nhưng Thạch Hạo không hề nhượng bộ. Khi Thạch Hạo để lộ một phần khí tức, Ly Long nhận ra sát khí của kẻ từng giết sinh linh thuần huyết, lập tức lùi bước và cảnh báo mọi người không nên trêu chọc nó. Cuộc phong ba tiếp tục lan rộng khi người của hồ Ma Linh chế giễu Võ Vương phủ và tuyên bố Đại Ma Thần khó giữ được tính mạng, khiến Thạch Hạo lạnh lùng quay sang chất vấn đối phương có phải Ma Chu hay không."},{"chuong":295,"tieuDe":"Trấn Áp Ma Chu","tomTat":"Một thiếu niên tóc xanh đến từ hồ Ma Linh đã đối đầu Thạch Hạo, đồng thời đe dọa giết người của Võ Vương phủ và tuyên bố Thập Ngũ gia khó thoát khỏi cái chết. Thạch Hạo đứng ra ngăn cản, phá tan sát thuật tóc xanh rồi dùng một chưởng đánh văng đối phương, buộc hắn hiện nguyên hình Bích Ma Hắc Đồng Chu. Ma Chu vận dụng tám chân sắc bén cùng lụa nhện có khả năng ăn mòn để kết thành lưới và xích thần trật tự, nhưng Thạch Hạo chỉ dùng cốt văn cơ bản trong Nguyên Thủy Chân Giải hóa lửa đã thiêu hủy toàn bộ. Sau khi đánh Ma Chu trọng thương đến mức không thể đứng dậy, Thạch Hạo chỉ ra đối phương còn chưa viên mãn Hóa Linh cảnh, qua đó khiến mọi người kinh hãi nhận ra chính nó đã đạt tới cảnh giới viên mãn khi tuổi còn rất nhỏ. Cổ Linh Ngọc cùng các minh châu Hoàng Đô bàng hoàng trước chiến lực áp đảo ấy, còn người của Võ Vương phủ hết sức hả hê. Cuối cùng, Thạch Hạo dùng một chiếc chén nhỏ thu Ma Chu vào trong, xem nó là vị thuốc chính thuộc Thái Cổ Ngũ Độc để chuẩn bị luyện thần dược, đồng thời hé lộ rằng năm loài độc vật này từng là những cấm kỵ Ma Thần thời xa xưa."},{"chuong":296,"tieuDe":"Xung Đột Càng Trầm Trọng Hơn","tomTat":"Ma Chu bị phù văn trong chén sứ áp chế hoàn toàn, còn Thạch Hạo quyết giữ nó lại để làm chủ dược luyện thần dược hoặc đổi lấy bảo vật. Khi nhóm người thân cận hồ Ma Linh, trong đó có con cháu Võ Vương phủ nghiêng về phía Thạch Nghị, lên tiếng đòi thả Ma Chu, Thạch Hạo đã quở trách họ quên mất lập trường rồi quét cả bọn xuống hồ. Sự cường thế ấy nhận được đồng tình của nhiều con cháu vương hầu vốn bất mãn với cảnh người trong Hoàng Đô khúm núm trước các sinh linh thuần huyết. Thiên Hồ tiên tử cảnh báo rằng giữ Ma Chu sẽ dẫn tới đại họa và ngỏ ý nhận nó thay, nhưng Thạch Hạo vẫn thẳng thừng từ chối. Hỗn Thiên hầu cùng nhiều nhân vật quyền quý chủ động kết giao với Thạch Hạo, trong khi hắn nhận ra Ly Long, Tất Phương, Chư Kiền, Vân Hi và nhiều hậu duệ Thần Sơn cũng đã tụ hội tại đây, báo hiệu Hoang Vực sắp có biến động lớn. Cuối cùng, Thạch Tử Đằng dẫn theo nhiều cường giả đi chiến xa tới Thanh Lâm viên, đích thân yêu cầu phóng thích hậu duệ hồ Ma Linh. Bất chấp quan hệ huyết thống và áp lực bao trùm toàn trường, Thạch Hạo công khai cự tuyệt, mở màn cuộc đối đầu trực diện đầu tiên giữa hai người."},{"chuong":297,"tieuDe":"Không Khoan Nhượng","tomTat":"Thạch Tử Đằng đích thân yêu cầu giao trả con nhện xanh, nhưng Thạch Hạo kiên quyết cự tuyệt, đồng thời âm thầm chuẩn bị vận dụng Bất Diệt Kim Thân hoặc tiểu tháp nếu cuộc đối đầu thật sự bùng nổ. Trước sức ép và lời đe dọa của các cường giả Võ Vương phủ, Thạch Hạo không hề nhượng bộ, còn chế giễu họ mang huyết mạch họ Thạch mà cam tâm dựa vào thế lực nhện lớn ở hồ Ma Linh. Khi bị truy hỏi sư môn, nó tự xưng là truyền nhân Cung điện Chí Tôn, một truyền thừa cổ xưa mỗi đời chỉ có một đệ tử, khiến lai lịch của nó trở nên khó lường sau lời xác nhận của Thiên Hồ tiên tử và Nguyệt Thiền tiên tử. Thạch Tử Đằng lấy danh nghĩa giải cứu sư điệt để tìm cớ ra tay, nhưng Thạch Hạo nhìn thấu dụng ý, công khai tuyên bố mình đến Hoàng Đô để quyết chiến với Thạch Nghị và thách hắn động thủ ngay nếu muốn trừ khử đối thủ của con mình. Khi người Võ Vương phủ chuẩn bị áp sát, Thiên Hồ tiên tử bất ngờ dùng danh nghĩa Tiệt Thiên giáo đứng ra bảo vệ Thạch Hạo, buộc phe Thạch Tử Đằng phải kiêng dè. Ngay sau đó, Nguyệt Thiền tiên tử hỏi ngày Thạch Nghị trở về dự đại thọ Nhân Hoàng, khiến mọi người nhận ra hai đại giáo dường như đang lần lượt lựa chọn hai thiếu niên Chí Tôn đối địch, đẩy bầu không khí tại hiện trường đến mức căng thẳng cực độ."},{"chuong":298,"tieuDe":"Lao Tù Hoang Vực","tomTat":"Nguyệt Thiền đứng ra giảng hòa, khiến Thạch Hạo đồng ý lưu mạng cho Ma Chu, nhưng nó vẫn kiên quyết giam giữ đối phương để trừng trị. Thạch Tử Đằng không thể cứu sư điệt nên ngầm cảnh cáo rằng một lão nhân đáng sợ của hồ Ma Linh đang ở Hoàng Đô, song Thạch Hạo không hề nhượng bộ và còn công khai chỉ trích những người của Võ Vương phủ dựa thế ngoại nhân. Sau khi Thạch Tử Đằng rời đi, Thiên Hồ tiên tử đề nghị nhận Ma Chu để luyện thần dược, nhưng Thạch Hạo quyết định tự giữ vì biết mối thù với hồ Ma Linh đã khó hóa giải. Cuộc đối đầu khiến các thiên tài tại tụ hội thu lại vẻ kiêu căng, còn Thạch Hạo dùng Trùng Đồng tìm kiếm và mua được hai loại vật liệu trước khi rời đi. Trên đường ra ngoài, Thiên Hồ tiên tử tiết lộ Hoang Vực vốn là một lao tù cổ xưa, từng giam cầm nhiều kẻ ác và hiện vẫn tồn tại hậu nhân mang tội huyết cùng những sinh linh ngoại lai bí ẩn. Nàng cho biết đại loạn sắp tới có thể tạo ra Thần Linh chân chính, đồng thời mời gọi Thạch Hạo gia nhập Tiệt Thiên giáo để tranh đoạt vận may. Cuối cùng, nàng hé lộ rằng Hoang Vực cất giấu một thứ phi phàm, chính là nguyên nhân khiến các đại giáo vô thượng nhúng tay và cuộc đại loạn sắp bùng nổ."},{"chuong":299,"tieuDe":"Tặng Đầu Người","tomTat":"Sau khi ma nữ rời khỏi Thanh Lâm viên, Thạch Hạo mang theo những nghi vấn về hậu nhân tội huyết và Thần Linh Hoang Vực, rồi trưng dụng chiến xa của Liễu Hàn để trở về khách sạn Hổ Môn. Tại viện riêng, nó rơi vào sát cục do một văn sĩ trung niên cảnh giới Minh Văn cùng bốn kẻ khác bố trí nhằm diệt trừ mình trước khi trưởng thành. Thạch Hạo mở mười Động Thiên nuốt sạch đạo hỏa, sau đó thi triển bảo thuật Côn Bằng phá hủy quạt bốn màu và đánh trọng thương kẻ cầm đầu. Khi phát hiện những kẻ còn lại đang ẩn nấp, nó dung hợp Bất Diệt Kim Thân, giam cầm cả khu vực rồi chém đầu toàn bộ năm người. Từ di vật và tộc huy trên thi thể, Thạch Hạo xác định những kẻ ám sát đến từ Võ Vương phủ và Vũ tộc, liền đặt từng thủ cấp vào hộp quà, gửi bốn hộp tới Võ Vương phủ và một hộp tới Vũ Vương phủ. Khi các hộp được mở ra, người trong Võ Vương phủ đều biến sắc, còn Thạch Tử Đằng giận dữ đập nát bàn đá vì hiểu đây là lời khiêu khích và cái tát công khai của Thạch Hạo."},{"chuong":300,"tieuDe":"Vũ Tộc Phẫn Nộ","tomTat":"Những kẻ được phái đi áp chế Thạch Hạo đã bị giết rồi gửi trả về đầy nhục nhã, khiến Thạch Tử Đằng lạnh mặt và sai người dò hỏi tung tích Vũ Lâm. Cùng lúc, Vũ Vương phủ nhận được chiếc hộp chứa đầu Vũ Lâm, lập tức điều động một đội tinh anh bao vây khách sạn Hổ Môn nhằm trả thù và khôi phục uy danh. Trước lời tuyên án ngang ngược của Vũ tộc, Thạch Hạo thẳng thừng chế giễu sự tự phụ của họ, đồng thời khơi lại nỗi nhục từng bị Đại Ma Thần đại náo. Khi giao chiến bùng nổ, nó tay không đánh vỡ ma đao, trọng thương một tuấn kiệt trẻ tuổi, sau đó hợp nhất với người tí hon màu đen để nâng chiến lực lên cấp Minh Văn cảnh. Thạch Hạo chống lại bảo thuật mưa sấm, liên tiếp phá hủy các bảo cụ và giết một cao thủ trung niên, khiến cả đội vây công kinh hãi. Cuối cùng, nó chủ động để lộ dung mạo Hùng Hài Tử, xác nhận mình là hậu duệ của người từng đại náo Vũ phủ và tuyên bố sẽ noi theo tổ phụ, đích thân tới Vũ Vương phủ."}];
